INSERT INTO `dlcs` (`id`, `videojuego_id`, `nombre`, `fecha_lanzamiento`, `descripcion`, `imagen_url`, `banner_url`, `dificultad_platino`, `duracion_estimada`, `trofeos_offline_oro`, `trofeos_offline_plata`, `trofeos_offline_bronce`, `trofeos_online_oro`, `trofeos_online_plata`, `trofeos_online_bronce`, `trofeos_perdibles`, `trucos_afectan`, `dificultad_afecta`, `comentario`, `fecha_adicionado`) VALUES
<<<<<<< HEAD
	(1, 3, 'Phantom Liberty', NULL, '', 'https://cf.geekdo-images.com/L7IBtEC057WUrz7_Ccyq7Q__imagepage/img/bJr1Z4RCdjDzWxqILQMwhWBTc8g=/fit-in/900x600/filters:no_upscale():strip_icc()/pic8508338.png', 'https://images6.alphacoders.com/132/1320691.jpeg', '4 sobre 10', '15', 0, 0, 13, 0, 0, 0, '', 0, 0, NULL, '2026-06-18 15:41:13'),
	(2, 15, 'The Witcher 3: Wild Hunt - Hearts of Stone', NULL, '<p>Independientemente del camino que escojas para empezar Hearts of Stone, simplemente completa la historia. Siguiendo las misiones principales, así como la secundaria "Rosa sobre campo de Gules" que recibirás después de una de las primeras misiones automáticamente, así como "De las lejanas costas de Ofir" completarás algún trofeo más (o no, ya que uno está bugueado). Para cuando termines conseguirás:</p><p><br></p><ul><li>No pienso besar eso&nbsp;</li><li>Conservador de pesadillas&nbsp;</li><li>Lo pactado obliga&nbsp;</li><li>Rosa silvestre sin espinas&nbsp;</li><li>Ya vestía Ofiri antes de que estuviera de moda&nbsp;</li></ul><p>Aparte de los trofeos relacionados con la historia, simplemente asegúrate de prestar atención a los siguientes trofeos perdibles:</p><ul><li>Que empiece la fiesta!&nbsp;</li><li>Comprador compulsivo&nbsp;</li><li>Solo contra el mundo&nbsp;</li><li>Consigue los trofeos adicionales no relacionados con misiones ni perdibles</li></ul><p>Una vez terminas la expansión, tienes un par de trofeos a hacer que requieren unas habilidades concretas. Si necesitas resetear tus habilidades, la siguiente imagen muestra la ubicación de un mercader en Novigrado que siempre tiene una poción para hacer un respec. Lo recomendable sería comprarla, usarla, hacer un guardado manual, asignar habilidades, conseguir un trofeo, cargar la partida salvada, hacer la segunda reasignación para el otro trofeo y cargar de nuevo para resignar a tu gusto (porque seguro que en tu primera partida, desperdiciaste algún punto).</p><p class="ql-align-center"><img src="http://i.imgur.com/602rpxM.jpg" style="width: auto !important; height: auto !important; max-width: 800px !important; display: inline-block !important;"></p><ul><li>Devolver al remitente&nbsp;</li><li>Me estoy quitando&nbsp;</li><li>Vacasesino&nbsp;</li><li>¡Mola tu estilo, colega!&nbsp;</li><li>Lo has bordado&nbsp;</li></ul>', 'https://image.api.playstation.com/vulcan/ap/rnd/202211/0909/lWIC0RHSx3hy3KU4dDRpTYEJ.png?w=620&thumb=false', 'https://image.api.playstation.com/vulcan/ap/rnd/202211/1010/7aPM7WovOcEgv1hYZFzndfbX.png?w=2048&thumb=false', '5 sobre 10', '20 horas', 0, 0, 13, 0, 0, 0, '<ul><li>Que empiece la fiesta!</li><li>Comprador compulsivo</li><li>Solo contra el mundo&nbsp;</li></ul>', 0, 0, NULL, '2026-06-18 18:29:25'),
	(3, 15, 'The Witcher 3: Wild Hunt - Blood and Wine', NULL, '<p><strong>Consejos para la 1 partida:</strong></p><p><br></p><p>Esta segunda expansión pone punto y final a la colosal aventura de The Witcher 3. Lo más recomendable es olvidarse de los trofeos y disfrutar lo máximo posible junto a Geralt de Rivia. En caso de saltarse algún trofeo perdible siempre queda la opción de jugar únicamente a la expansión.</p><p><br></p><p><strong>Trofeos Perdibles – Coleccionables – Trofeos Acumulabes</strong></p><p>Aquellos que no queráis dejaros ningún trofeo debéis tener en cuenta que nada más empezar debéis matar a Golyat de un disparo en el ojo. Por otra parte, durante el transcurso de toda la expansión debéis ir cumpliendo las cinco virtudes de los caballeros para el correcto cumplimiento de una misión secundaria. Cerca del final, el propio juego os avisará de que sería recomendable realizar un guardado manual debido a los acontecimientos que vendrán, hacedle caso. Y si en aquel momento aún no habéis hecho la secundaria del torneo, realizadla, puesto que se perderá. De esta manera podréis sacar los dos finales de los trofeos.</p><p><br></p><p><strong>Limpieza de Trofeos</strong></p><p>Una vez acabada la expansión podéis realizar trofeos como el de las búsquedas de los sets de las escuelas de brujo, el de nivel gran maestro, el de mutágeno, el de gwynt (baraja y torneo), etc. Hay trofeos que no deben realizarse en ningún momento en concreto.</p><p><br></p>', 'https://image.api.playstation.com/vulcan/ap/rnd/202211/0909/EPn8jNEugDBrQJ1BRKlhHGVu.png?w=620&thumb=false', 'https://i.postimg.cc/JzXfYz6p/tw3bw.png', '7 sobre 10', '25 horas', 0, 0, 13, 0, 0, 0, '<p><span style="background-color: rgb(35, 31, 54); color: rgb(20, 20, 20);"><img src="http://www.ps3trophies.org/images/site/icons/trophy_bronze.png" style="width: auto !important; height: auto !important; max-width: 800px !important; display: inline-block !important;"></span>El último gran héroe </p><p><span style="background-color: rgb(35, 31, 54); color: rgb(20, 20, 20);"><img src="http://www.ps3trophies.org/images/site/icons/trophy_bronze.png" style="width: auto !important; height: auto !important; max-width: 800px !important; display: inline-block !important;"></span>El rey de chirona </p><p><span style="background-color: rgb(35, 31, 54); color: rgb(20, 20, 20);"><img src="http://www.ps3trophies.org/images/site/icons/trophy_bronze.png" style="width: auto !important; height: auto !important; max-width: 800px !important; display: inline-block !important;"></span>Sir Invictus</p><p><span style="background-color: rgb(35, 31, 54); color: rgb(20, 20, 20);"><img src="http://www.ps3trophies.org/images/site/icons/trophy_bronze.png" style="width: auto !important; height: auto !important; max-width: 800px !important; display: inline-block !important;"></span>La virtud hecha brujo </p><p><span style="background-color: rgb(35, 31, 54); color: rgb(20, 20, 20);"><img src="http://www.ps3trophies.org/images/site/icons/trophy_bronze.png" style="width: auto !important; height: auto !important; max-width: 800px !important; display: inline-block !important;"></span>Las uvas pisoteadas de la ira </p><p><span style="background-color: rgb(35, 31, 54); color: rgb(20, 20, 20);"><img src="http://www.ps3trophies.org/images/site/icons/trophy_bronze.png" style="width: auto !important; height: auto !important; max-width: 800px !important; display: inline-block !important;"></span>A ojo de buen ballestero </p>', 0, 0, NULL, '2026-06-18 18:36:59'),
