	(1, 1, 'El mejor de los Grandes Mensajeros', 'Has conseguido todos los trofeos de Death Stranding', 'PLATINO', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/13921/bbbdf9dd-4578-4905-bef1-fe181cddc792.png', '', ''),
