	(169, 4, 'El Mundo Verá la Esperanza de tu Lluvia', 'Completa el episodio 4: Gotas de lluvia.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/34699/8c360867-8e54-42bb-8c48-e96a1676141a.png', 'Trofeo parte de la historia.', ''),
