	(1289, 30, 'Entrenamiento de supervivencia', 'Aprende 25 mejoras de jugador.', 'PLATA', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/2397aeb7-dfa0-471d-bf62-bf7dfb82b22e.png', '', ''),
	(1290, 30, 'Gran calibre', 'Encuentra todas las armas.', 'PLATA', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/2b9542f2-0735-4612-a870-df8401599d48.png', '', ''),
	(1291, 30, 'En el campo', 'Encuentra 12 mesas de trabajo.', 'PLATA', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/cff0b96e-aa94-4758-a178-7e21841d4c15.png', '', ''),
	(1292, 30, 'Bricomaníaca', 'Fabrica todos los objetos.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/565b069f-cafb-42c9-8fee-5e3de7d7a54d.png', '', ''),
	(1293, 30, 'Manitas', 'Mejora un arma.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/65fcaa04-8648-41ff-978d-ebf6ef1e9ada.png', '', ''),
	(1294, 30, 'Aprendiz', 'Aprende una mejora de jugador.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/4385aaa6-f0d0-4b2b-b25d-b5354d11681c.png', '', ''),
	(1295, 30, 'Baraja de principiante', 'Encuentra 5 cartas coleccionables.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/44ed5c66-48e6-4281-b690-35cb9b96c6b2.png', '', ''),
	(1296, 30, 'En perfecto estado', 'Encuentra 5 monedas.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/9cd5c5c2-6850-4b82-9122-94fda570f41e.png', '', ''),
	(1297, 30, '¡Pero el sombrero es nuevo!', 'Ponle un sombrero a tu compañero.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/25c9e136-e644-4f4b-9a17-519ee6133cbb.png', '', ''),
	(1298, 30, '¡En el blanco!', 'Gana la competición de tiro.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/aba7259f-8444-4a7e-bbb1-d79cc88795db.png', '', ''),
	(1299, 30, 'Pon mi nombre ahí arriba', 'Consigue la puntuación más alta en el juego de tiro con arco.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/6bd915fa-d574-40e8-98c4-22f14da5fe38.png', '', ''),
	(1300, 30, 'Reliquia de los sabios', 'Encuentra el artefacto extraño.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/1b1b4657-d04d-41d6-af08-b462cf395233.png', '', ''),
	(1301, 30, 'La grandeza nace de pequeños comienzos', 'Encuentra el anillo grabado.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/10960/287a429e-e584-46a8-bbf4-3a1320ffcdb8.png', '', ''),
	(1302, 32, 'Todo por el planeta', 'Por haber conseguido todos los trofeos.', 'PLATINO', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/13310j34.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>El planeta te agradece todos los esfuerzos que has puesto en conseguir este exigente platino. Enhorabuena, como mínimo.</p>', ''),
	(1303, 32, 'El héroe infame', 'Por haber completado el capítulo 1.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/3554065g.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1304, 32, 'Ancha es Gaia', 'Por haber completado el capítulo 2.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/777d457b.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1305, 32, 'Se hace camino al andar', 'Por haber completado el capítulo 3.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/40061be5.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1306, 32, 'Un desfile accidentado', 'Por haber completado el capítulo 4.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/6ddg537d.png?5f889ea35a5e099f584c5f6f99c567e8', '', ''),
	(1307, 32, 'La segunda venida de Jénova', 'Por haber completado el capítulo 5.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/b88364gg.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1308, 32, 'Vacaciones de alto riesgo', 'Por haber completado el capítulo 6.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/gjj73513.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1309, 32, 'El precio del progreso', 'Por haber completado el capítulo 7.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/dgg81b0b.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1310, 32, 'Huida del paraíso', 'Por haber completado el capítulo 8.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/j0015e61.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1311, 32, 'Los gritos del planeta', 'Por haber completado el capítulo 9.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/13310j7g.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1312, 32, 'El valle de las estrellas fugaces', 'Por haber completado el capítulo 10.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/3554067d.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1313, 32, 'Soldado venido a menos', 'Por haber completado el capítulo 11.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/777d450e.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1314, 32, 'Siempre nos quedará el Gold Saucer', 'Por haber completado el capítulo 12.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/555b3g78.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1315, 32, 'Lo prometido es deuda', 'Por haber completado el capítulo 13.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/0001dj35.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1316, 32, 'El reencuentro', 'Por haber completado el capítulo 14.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/8jj46057.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Relacionado con el transcurso natural del juego.</p>', ''),
	(1317, 32, 'Soldado a bordo', 'Por haber ganado tu primer combate.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/eee81g30.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Más autoexplicativo, imposible. Será de los primeros trofeos que consigas.</p>', ''),
	(1318, 32, 'Despiadado', 'Por haber atacado el punto débil de un enemigo por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/40061b15.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Atacar el punto débil del enemigo es una de las mecánicas básicas de este sistema de combate y vas a hacerlo millones de veces durante el juego. Para ello, primero tendrás que escanear a un enemigo con ayuda de la Materia `Análisis` para conocer el elemento al que es débil. Después, tan solo lanza una magia del elemento al que es débil y el trofeo es tuyo.</p>', ''),
	(1319, 32, 'Compañeros de armas', 'Por haber ayudado a un aliado inmovilizado por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/6ddg535d.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Habrá ciertos enemigos que usarán partes de su cuerpo para agarrar y atrapar a un personaje, dejándolo completamente inmovilizado y a merced del enemigo. Cuando esto suceda, la parte del cuerpo con la que hayan atrapado al compañero tendrá salud propia; es en este momento cuando tienes que cambiar a otro personaje y golpear a la parte del cuerpo hasta debilitarla. De esta forma, liberarás al compañero y ganarás este trofeo. Seguramente lo hagas durante el tutorial del Capítulo 1.</p>', ''),
	(1320, 32, 'Repartiendo cera', 'Por haber dejado vulnerable a un enemigo por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/b883646g.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Dejar a un enemigo en estado de vulnerabilidad será la clave para hacerte con la victoria en más de una ocasión. Dejarás vulnerables a los enemigos en cuanto llenes la barra naranja que aparece debajo de su salud, la cual, para llenarla, tendrás que atacar la debilidad del enemigo en cuestión o fatigarle. Para ambas cosas, necesitarás escanearlos con la Materia `Análisis` y así saber cómo atacarlos. Lo lograrás durante el tutorial del Capítulo 1.</p>', ''),
	(1321, 32, 'Los límites, para quien los tenga', 'Por haber utilizado un Límite por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/gjj73533.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Para poder lanzar este poderoso ataque, primero tendrás que llenar la barra de límite de un personaje, la cual se llenará al recibir golpes o dejar a los enemigos en estado de vulnerabilidad. En cuanto esté llena, abre con :equis: el menú, elige `Límite` y lo lanzas para recibir el trofeo.</p>', ''),
	(1322, 32, 'Invocando, que es gerundio', 'Por haber llamado al combate a una invocación por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/dgg81b1b.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Durante las peleas, verás en algún momento que aparece una barra morada en la parte derecha. Cuando ésta aparezca, quiere decir que puedes lanzar la invocación que tengas equipada, necesitarás dos barras de BTC completas para poder lanzarla, eso sí. Para lanzarla, pulsa :equis:, entra en el menú `Invocación` y elígela para recibir el trofeo.</p>', ''),
	(1323, 32, 'Los amigos están para ayudar', 'Por haber ejecutado una acción sincronizada por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/j0015e51.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Las acciones sincronizadas son una nueva mecánica de este juego y podrás usarlas desde el momento en que tengas dos personajes en la party. Los efectos de estas habilidades son variables en función de los personajes, pudiendo activarse con combinaciones como, por ejemplo, :r1: + :triangulo: o :r1: + :circulo: . Lo conseguirás durante el tutorial del Capítulo 1.</p>', ''),
	(1324, 32, 'Dos son mejor que uno', 'Por haber ejecutado una habilidad sincronizada por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/13310j0g.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Estas habilidades son unos poderosos movimientos que podrás lanzar en pareja con otro personaje, con efectos variables en función de la habilidad y los personajes. Estas habilidades solo tienen un único uso por combate y cada una de ellas se activa tras haber gastado previamente un determinado número de segmentos BTC con cada uno de los personajes protagonistas de la acción. Por ejemplo, Cloud y Tifa tienen una habilidad sincronizada llamada `Compañeros de caza` que podrás lanzarla en combate cuando Cloud y Tifa hayan consumido tres segmentos de BTC cada uno. Una vez cumplas los requisitos, abre el menú con :equis:, escoge `Habilidades sincronizadas` y elige la habilidad que quieras lanzar. Lo conseguirás durante el tutorial del Capítulo 1.</p>', ''),
	(1325, 32, 'Donde haya guiles, habrá mercenarios', 'Por haber terminado tu primer encargo.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/3554060d.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Ver Trofeo&nbsp;El trabajo honra al mercenario</p>', ''),
	(1326, 32, 'Uno con su arma', 'Por haber perfeccionado tu pericia con un arma.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/777d454e.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Ver Trofeo&nbsp;Destreza inigualable&nbsp;</p>', ''),
	(1327, 32, 'Entrando en materia', 'Por haber aumentado de nivel una materia por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/555b3g38.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Irás ganando PH para subir el nivel de las materias simplemente matando enemigos y ganando batallas. Ni siquiera es necesario que el personaje esté participando en la batalla para que sus materias reciban PH; todas las materias que lleven todos los personajes de la party recibirán PH.</p>', ''),
	(1328, 32, 'Otra partida y nos vamos', 'Por haber subido tu rango de jugador de sangre de la reina por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/0001djd5.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>El rango de sangre de la reina, el minijuego de cartas oficial de Rebirth, aumenta a base de victorias contra otros jugadores de cartas. Estos vienen marcados en el minimapa con un número dorado, indicando su rango y que pueden ser retados. En la ciudad de Kalm del Capítulo 2 hay tres jugadores distintos, exactamente los tres que necesitas para subir el primer rango y conseguir este trofeo. Cabe destacar que, para el rango, solo cuenta la primera victoria contra cada jugador, las victorias que sumes haciendo revanchas contra jugadores a los que ya has ganado no cuentan para el rango.</p>', ''),
	(1329, 32, 'Buscador de tesoros', 'Por haber descubierto la ubicación de un tesoro oculto por primera vez.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/8jj46067.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Estos tesoros ocultos aparecen por las zonas de mundo abierto y, como tal, no aparecen marcados en el mapa hasta que no nos aproximamos a ellos. El primero de ellos nos lo podemos encontrar en el Capítulo 2 directamente al este de Kalm, pero nos encontraremos infinidad de ellos por las diferentes regiones sin apenas buscarlos. Cuando entremos en una zona de tesoro oculto, nos aparecerá un marcador con los cofres escondidos que tiene el área, siendo normalmente 2 ó 3 cofres con contenido variado (objetos curativos, objetos restauradores de PM, accesorios...)</p><p>Cuando consigamos abrir los cofres del área, la ubicación se dará por completada y recibiremos el trofeo.</p><p><br></p><p>NOTA: Los cofres ocultos no cuentan como informe de viaje a la hora de completar una región.</p>', ''),
	(1330, 32, 'Partidario del transporte público', 'Por haber rehabilitado tres paradas de chocobotaxi.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/eee81g10.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Verás varias paradas de chocobotaxi conforme explores las zonas de mundo abierto, las cuales te permitirán descansar en ellas usando el objeto `Cojín` o simplemente como puntos de viaje rápido, para facilitar la navegación por el mapa. No aparecen marcadas en el mapa hasta que no te aproximes a ellas, pero darás con varias de ellas casi sin querer o con la ayuda de los chocobitos, quienes te indicarán el camino exacto hacia ellas. Para rehabilitar una parada, necesitas levantar la señal caída que queda en el lado izquierdo de la parada manteniendo pulsado :triangulo:. Una vez hayas rehabilitado tres paradas distintas, el trofeo es todo tuyo.</p><p><br></p><p>NOTA IMPORTANTE: siempre que encuentres una parada con la ayuda de un chocobito; acaríciale cuando la rehabilites. No influye en los trofeos ni en nada, simplemente no seas desagradecido/a con ese pequeñín, vaya.</p>', ''),
	(1331, 32, 'Aquí huele a tesoro', 'Por haber encontrado dos tesoros enterrados por conejos.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/40061bb5.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Desde el momento en que tengas disponible al chocobo en el Capítulo 2, eventualmente te encontrarás con unos conejos que, al verlos, saltará un icono sobre la cabeza del chocobo, indicando la presencia de objetos enterrados por los conejos. Cuando veas este icono, mantén pulsado `:arriba: para olfatear la zona y averiguar la dirección del objeto enterrado, el cual deberás desenterrar con :abajo: cuando te coloques en la casilla exacta donde está enterrado, fácilmente visible por un evidente brillo. Desentierra dos tesoros de esta forma y trofeo nuevo.</p>', ''),
	(1332, 32, 'Ahora trabajas para mí', 'Por haber derrotado a una invocación en el simulador y obtenido su materia.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/6ddg533d.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Las peleas contra invocaciones están disponibles en el simulador de combates de Chadley y hay una por región. Están disponibles desde el primer momento en que entres a una región y hables con Chadley, pero que sea el primer momento no quiere decir que sea el mejor, ya que si vas a pelear con la invocación `a pelo`, lo más normal es que te lleves la paliza de tu vida. Lo ideal, antes de enfrentar a cada invocación, es analizar los llamados "cristales de informe de invocación", los cuales aparecen marcados en el mapa y hay tres en cada región, los cuales están directamente vinculados con el poder de la invocación en cuestión. A la hora de analizar estos cristales, tendrás que hacer un breve "minijuego" de pulsar los botones que aparecen secuenciados en una gran circunferencia. Cada análisis de cristal hará que la invocación quede más debilitada, pudiendo debilitar su fuerza hasta tres puntos al analizar todos los cristales, permitiendo así poder combatir a la invocación con muchas más garantías de victoria.</p><p><br></p><p>En resumen: Analizar los tres cristales de la región y después pelear con la invocación. Al vencer a la invocación, recibirás este trofeo.</p>', ''),
	(1333, 32, 'Ayudante de investigación', 'Por haber completado cinco objetivos de informes de viaje.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/b883644g.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Ver Trofeo&nbsp;Experto explorador&nbsp;</p>', ''),
	(1334, 32, 'Investigador de campo', 'Por haber completado cincuenta objetivos de informes de viaje.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/gjj73553.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Ver Trofeo&nbsp;Experto explorador&nbsp;</p>', ''),
	(1335, 32, 'Experto explorador', 'Por haber completado todos los informes de viaje de una región.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/dgg81bbb.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Se resume en completar todo lo que proporcione un informe de exploración de la región: Torres de comunicación, Zonas de caza, Cristales de invocación, Fuentes Vitales y Protomaterias. Puedes ver el progreso de los informes abriendo el mapa de la región en cuestión y viendo los datos desglosados en la parte inferior izquierda de la pantalla. Por norma general, todas esas actividades aparecen marcadas en el mapa, pero para poder ver algunas, necesitarás completar otras antes.</p><p><br></p><p>NOTA: Solo cuentan para el trofeo las actividades mencionadas, el resto de actividades como los Tesoros ocultos, Enclaves fotográficos o Paradas de chocobotaxi no cuentan.</p>', ''),
	(1336, 32, 'La chunga vida del empresario', 'Por haber obtenido la protomateria de los pastizales.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/j0015ee1.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Para conseguirla, has de completar los cuatro informes de búsquedas del mapa que están marcados con el dibujo de un gran cofre de color naranja en la Zona de los pastizales. En el momento en que completas uno, aparece el siguiente. Son objetivos bastante sencillos que se resumen en pelear. En el cuarto y último evento de estas búsquedas, podrás comprar la protomateria por 2.000g y obtener el trofeo.</p>', ''),
	(1337, 32, 'Recreación histórica reinventada', 'Por haber obtenido la protomateria de la región de Junon.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/13310jjg.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Para conseguirla, has de completar los cuatro informes de búsquedas del mapa que están marcados con el dibujo de un gran cofre de color naranja en la Región de Junon. Esta cadena de misiones se compone de un minijuego llamado `Fuerte Cóndor` (que si has jugado a FF7 Intergrade, conocerás perfectamente) en el que tendrás que derribar las defensas de tu oponente con ayuda de tus unidades de combate. Cada nivel será más complicado que el anterior, lo mejor que se te puede aconsejar es que `sobrecargues` de unidades uno de los dos caminos en el que tengas vía libre y el otro lo dejes parcialmente descubierto, pues por norma general, tus defensas pueden aguantar bastante sin necesidad de que estés defendiendo y cargarse ellas solas a los enemigos que vengan. A partir de aquí, todo es lanzar unidades que sean efectivas contra las que lanzará el enemigo (puedes anticiparte vigilando las dos líneas para saber qué es lo que va a lanzar en cada camino y actuar en consecuencia) y usar los héroes cuando sea oportuno.</p><p><br></p><p>Al acabar la cuarta misión de esta cadena de misiones, conseguirás la protomateria y el trofeo.</p>', ''),
	(1338, 32, 'No hay cactilio sin espinas', 'Por haber obtenido la protomateria de la región de Corel.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/3554066d.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Para conseguirla, has de completar los cuatro informes de búsquedas del mapa que están marcados con el dibujo de un gran cofre de color naranja en la Región de Corel. Saldrás a esta región durante los Capítulos 8 y 9, donde podrás completar las dos primeras misiones relacionadas con la protomateria, pero las dos restantes solo podrás completarlas a partir del final del Capítulo 12. Estas misiones consisten en utilizar unas estatuillas de cactilio para encontrar, con ayuda del láser que sueltan cuando las levantas, unos `altares` especiales que abren unas cámaras selladas. Dentro de estas cámaras, harás unos minijuegos de eliminar Cactilios con Yuffie o con Aeris. Al acabar las cuatro misiones, tendrás un pequeño y sencillo combate final y obtendrás el trofeo en cuanto lo superes.</p>', ''),
	(1339, 32, 'Turco honorario', 'Por haber obtenido la protomateria de la región de Gongaga.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/777d455e.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Para conseguirla, has de completar los cuatro informes de búsquedas del mapa que están marcados con el dibujo de un gran cofre de color naranja en la Región de Gongaga. A diferencia de las de otras regiones, estas búsquedas se reducen a simples combates. En cuanto completes la última misión de esta cadena de misiones, el trofeo será tuyo.</p>', ''),
	(1340, 32, 'Comando planetario', 'Por haber obtenido la protomateria de la región de Cañón Cosmo.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/555b3gg8.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Para conseguirla, has de completar los cuatro informes de búsquedas del mapa que están marcados con el dibujo de un gran cofre de color naranja en la Región de Cañón Cosmo. El minijuego de esta cadena de misiones es muy similar al del Fuerte Cóndor, ya que también se trata de desplegar unidades (esta vez robóticas) con patrones de comportamiento en combate que tendremos que configurar nosotros mismos, con el objetivo de tumbar a un jefe colocado en la parte central del escenario. La mejor recomendación para acabar rápido este minijuego es que, a la hora de configurar cada unidad, elijas la configuración recomendada por la IA continuamente. Después, solo es cuestión de usar unidades con un elemento que sea poderoso frente a los robots que te lanza la máquina. Eso, más lanzar alguna Revitalia o cualquier ataque ofensivo de portal cuando sea preciso, sería todo para superar cada nivel del minijuego. En cuanto completes el último nivel de esta cadena de misiones, el trofeo será tuyo.</p>', ''),
	(1341, 32, 'Paseador de túnicas negras', 'Por haber obtenido la protomateria de la región de Nibel.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/0001djj5.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Para conseguirla, has de completar los cuatro informes de búsquedas del mapa que están marcados con el dibujo de un gran cofre de color naranja en la Región de Nibel. Al igual que sucedía con otras protomaterias del juego, conseguir esta es algo bastante simple, ya que los misiones son de ir al punto A, matar enemigos... y poco más. En cuanto completes la última búsqueda de esta cadena de misiones, el trofeo será tuyo.</p>', ''),
	(1342, 32, 'El espadachín legendario', 'Por haber derrotado a Gilgamesh.', 'PLATA', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/8jj46007.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Para ir a por Gilgamesh has de cumplir dos requisitos: Llegar al Capítulo 13 y conseguir las protomaterias de todas las regiones. Cuando cumplas esos requisitos, podrás dirigirte a una ubicación al norte del Océano Medigaiano con la ayuda del potrillo para superar una serie de combates previos, y finalmente medirte con Gilgamesh.</p><p>Gilgamesh tiene debilidad al fuego y es vulnerable a las magias `Bio` y la gran mayoría de magias `de debufo`. Dado que este enemigo siempre ataca con ataques físicos, es recomendable llevar a alguien con una Materia Protectora vinculada a una Materia de Área para lanzar una Barrera sobre todos los aliados, además de llevar materias que permitan curar a cada uno de los personajes que uses. Por lo demás, es cuestión de esquivar y bloquear sus rapidísimos ataques hasta vencerlo. Cuando plante su escudo de Genji, debilítalo para fatigarle. Al acabar con él, recibirás las recetas para sintetizar varios objetos de Genji, la materia de invocación de Gilgamesh y, por supuesto, este trofeo.</p>', ''),
	(1343, 32, 'Amigo de los moguris', 'Por haber aumentado al máximo la popularidad del bazar moguri.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/eee81gg0.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>En prácticamente todas las regiones te encontrarás con los bazares de moguri, éstos vienen marcados en el propio mapa, haciendo un total de 7 bazares moguri disponibles en el juego. Para conseguir el trofeo, tienes que superar el minijuego `pilla-pilla` de cada uno de estos bazares, sin importar lo más mínimo el tiempo o cualquier otro requisito. Cada minijuego se irá complicando más y más, pero mientras aprendas a esquivar bien los ataques de los moguris, no supone un gran problema.</p>', ''),
	(1344, 32, 'Apoyando las ciencias', 'Por haber facilitado el desarrollo de todas las materias de Chadley.', 'PLATA', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/40061b65.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Con la ayuda de los datos que obtengas en cada región completando cada uno de los `Informes de viaje`, podrás desarrollar materias exclusivas hablando con Chadley. Este trofeo te obligará a completar los informes de viaje de absolutamente todas las regiones, incluida la región secreta de Gilgamesh disponible a partir del Capítulo 13. Cabe destacar que, para conseguir el trofeo, tienes que comprar todas las materias que vende, incluso las que están repetidas. Es decir, que si vende cinco unidades de una materia concreta, tienes que comprar esas cinco unidades también. Básicamente está pensado para que te queden 0 unidades de datos en todas las regiones tras haber comprado todo lo que vende.</p>', ''),
	(1345, 32, 'Séptima Compañía, ¡firmes!', 'Por haber reunido para el desfile a todos los infantes de la Séptima Compañía.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/6ddg53gd.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Este trofeo se consigue durante la recta final del Capítulo 4. Cuando tengas activo el objetivo `Reúne a la Séptima Compañía`, tendrás que reclutar a los 10 escuadrones de infantería para el desfile, dispersos entre las calles y los interiores. Solo está rodeada la zona donde están, pero conforme te vayas acercando a un escuadrón, verás una marca azul en la cámara con la localización precisa del más cercano. Cuando tengas a los 10, el trofeo será tuyo.</p>', ''),
	(1346, 32, 'Séptima Compañía, ¡marchen!', 'Por haber ganado la medalla a la mejor marcha en el desfile de Junon.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/b883643g.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Debes ganar el desfile de Junon durante el Capítulo 4. Crea un escuadrón con 2 Granaderos, 2 Antidisturbios y 1 Incendiario e intenta hacerlo medianamente bien. No tiene que ser perfecto, pero necesitarás algo más de 100.00 puntos para ganar, la cantidad mínima exacta de momento se desconoce. Los botones de color rojo indican que solo tienes que pulsarlos una vez, los amarillos tienes que pulsarlos repetidamente y los azules tienes que mantenerlos pulsados hasta que te lo indiquen. Si en el momento en que anuncien el ganador no te den la medalla, cierra el juego y entra de nuevo o carga una partida justo antes de que empiece el desfile para volverlo a intentar.</p>', ''),
	(1347, 32, 'La privanza de la reina', 'Por haber ganado todas las partidas del Torneo de Sangre de la Reina a bordo del Shinra Ocho.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/gjj73573.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Este torneo lo jugarás como parte de la historia durante el Capítulo 5. Tendrás que derrotar a los 5 rivales del torneo (con posibilidad de revancha si pierdes contra alguien) para poder lograr el trofeo. La mejor recomendación posible es que tengas un guardado manual antes de jugar contra cada contrincante, en caso de que la partida se te dé mal y pierdas. Con eso en cuenta, mientras conozcas bien las reglas del juego y tengas un mazo mínimamente actualizado, no deberías tener problemas para ganar.</p>', ''),
	(1348, 32, 'Ovación en pie', 'Por haber obtenido una calificación de rango S o superior por tu actuación en el teatro del Gold Saucer.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/dgg81b8b.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Este trofeo lo realizarás en el Capítulo 12 durante la cita con el personaje que te toque. El personaje con el que hagas la cita no es relevante para lograr este trofeo.</p><p>En cierto momento de la cita llegarás a un minijuego de una obra de teatro que consiste en, básicamente, pulsar botones cuando salgan en pantalla. Una serie de QTE`s divididos en tres fases, en esencia. Es bastante fácil si te guías por la dirección donde vienen los botones para saber cuál es el botón que tienes que pulsar antes de que se muestre, incluso. Es decir, si por ejemplo el botón viene de la dirección derecha, ya sabes de antemano que tienes que pulsar :circulo: . Por suerte no es necesario hacerlo perfecto, pero sí tienes que acertar como mínimo la mayoría de los botones. Si ves que fallas mucho, puedes reiniciar el minijuego o cargar una partida guardada para volverlo a intentar.</p><p><br></p><p>NOTA: El trofeo saltará al final de toda la cinemática, un ratito después de darte la S.</p>', ''),
	(1349, 32, 'Una amistad de una estrella', 'Por haber desbloqueado la colección de Johnny y reunido diez artículos para exponer en ella.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/j0015e11.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Ver Trofeo&nbsp;Una amistad de siete estrellas&nbsp;</p>', ''),
	(1350, 32, 'Una amistad de tres estrellas', 'Por haber desbloqueado la colección de Johnny y reunido treinta artículos para exponer en ella.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/13310j1g.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Ver Trofeo Una amistad de siete estrellas&nbsp;</p>', ''),
	(1351, 32, 'Una amistad de cinco estrellas', 'Por haber desbloqueado la colección de Johnny y reunido sesenta artículos para exponer en ella.', 'PLATA', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/3554064d.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Ver Trofeo Una amistad de siete estrellas&nbsp;</p>', ''),
	(1352, 32, 'Una amistad de siete estrellas', 'Por haber informado a Johnny de que has completado su colección.', 'ORO', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/777d45de.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Tienes ante ti al trofeo responsable de que completes casi la totalidad del contenido que ofrece Final Fantasy VII Rebirth.</p><p>En el Capítulo 9, podrás completar el Encargo 1: El Vistamar a toda vela y esto te dará acceso a la `Colección de Johhny`, éstos son unos premios que podrás conseguir para su colección personal (anda que ya podría molestarse él en ir a conseguirlos, porque pide algunas cosas que...)</p><p>Cada uno de estos premios te pide hacer diferentes cosas; desde encontrar tesoros enterrados... hasta lograr superar minijuegos y desafíos de Chadley de auténtica locura. Puedes consultar en cualquier momento la Colección de Johhny yendo a la parte noroeste de Costa del Sol, hay un viaje rápido en esa dirección para ir directo con Johhny.</p><p>​</p><p>Dejo aquí una lista con cada uno de los premios y su requisito para ser desbloqueado:</p><p><br></p><p>1- Conseguir el mejor tiempo en el circuito `Galopada de Chocobo` en el Rancho de Billy.</p><p>2- Conseguir la mejor puntuación en los tres circuitos de `Bucle de Chocobo` en Cañón Cosmo.</p><p>3- Superar el mejor tiempo de supervivencia en el modo Estándar de `Salto de la rana` en el muelle de Bajo Junon.</p><p>4- Superar el mejor tiempo de supervivencia en el modo `Amenaza rotatoria` de `Salto de la rana` en el muelle de Bajo Junon.</p><p>5- Batir el mejor tiempo en el minijuego del Delfín en Bajo Junon.</p><p>6- Completar los cuatro niveles del `Fuerte Cóndor` en Dificultad Estratégica.</p><p>7 y 8- Ganar el Desfile de Junon durante el Capítulo 4. Ver Trofeo&nbsp;Séptima Compañía, ¡marchen!&nbsp;</p><p>9- Ganar el torneo de `Sangre de la reina` del Capítulo 5.</p><p>10- Superar la mejor puntuación en `Piratas al abordaje` en Costa del Sol.</p><p>11- Superar la mejor puntuación en la modalidad `Barco Fantasma` de `Piratas al abordaje` en Costa del Sol.</p><p>12 al 15- Completar todos los desafíos del `Carnaval de cartas` en Costa del Sol.</p><p>16- Batir el mejor tiempo de `Carrera salvaje` en Costa del Sol.</p><p>17- Batir el mejor tiempo de la modalidad `Contrarreloj` de `Carrera salvaje` en Costa del Sol.</p><p>18- Ganar a todos los rivales en el `Duelo de abdominales`.</p><p>19- Batir la mejor puntuación en el `G-Bike` de Gold Saucer.</p><p>20- Batir la mejor puntuación en la modalidad `Carrera avanzada` del `G-Bike` de Gold Saucer.</p><p>21 al 23- Ganar a todos los rivales del `Combate 3D` en Gold Saucer. Ver Trofeo&nbsp;Héroe no hay más que uno&nbsp;</p><p>24- Lograr la máxima puntuación en `Locura sideral` en Gold Saucer.</p><p>25- Lograr la máxima puntuación en la modalidad `Misión avanzada` de `Locura sideral` en Gold Saucer.</p><p>26 al 29- Ganar las copas de las `Carreras de chocobo` en Gold Saucer. Ver Trofeo&nbsp;Rey del chocobódromo&nbsp;</p><p>30 al 32- Ganar todos los duelos de `Desafíos de Sangre de la reina` en Gold Saucer.</p><p>33 al 36- Superar todos los combates del `Musculiseo` en Gold Saucer.</p><p>37- Conseguir un rango S general en el `Loveless` en el Capítulo 12.</p><p>38- Conseguir un rango S general en el `Loveless` en el Capítulo 12, durante la cita con Tifa.</p><p>39- Conseguir un rango S general en el `Loveless` en el Capítulo 12, durante la cita con Aerith.</p><p>40- Conseguir un rango S general en el `Loveless` en el Capítulo 12.</p><p>41- Conseguir un rango S general en el `Loveless` en el Capítulo 12, durante la cita con Yuffie.</p><p>42- Conseguir un rango S general en el `Loveless` en el Capítulo 12.</p><p>43- Conseguir un rango S general en el `Loveless` en el Capítulo 12.</p><p>44- Batir la mejor puntuación en `Choque en el desierto` de la Prisión de Corel.</p><p>45- Batir la mejor puntuación en la modalidad `Difícil` del `Choque en el desierto` de la Prisión de Corel.</p><p>46 al 48- Ganar todos los duelos de `Palestra de las bestias` en la Prisión de Corel.</p><p>49- Igualar o superar la mejor puntuación de los cuatro `Desafíos de los cactilios` en Corel.</p><p>50- Igualar o superar la mejor puntuación de los cuatro `Desafíos de los cactilios` en la modalidad `Estratégica` en Corel.</p><p>51- Superar los cuatro desafíos de `Comando robótico` en la modalidad Estratégica`.</p><p>52 y 53- Ganar todos los combates del `Simulador Versus Shinra` en la Mansión Shinra.</p><p>54 y 55- Ganar todos desafíos de Chadley. Ver Trofeo&nbsp;La pesadilla de los píxeles&nbsp;</p><p>56- Lograr, como mínimo, un Rango A en las seis partituras principales del Piano. Ver Trofeo&nbsp;Con la música a todas partes&nbsp;</p><p>57- Entregar todos los enclaves fotográficos a Enfoque, hay uno por región.</p><p>58- Alcanzar el rango de Campeón en `Sangre de la reina` ganando a todos los duelistas de todas las regiones.</p><p>59- Superar el Encargo 9: El Desafío del jugón. Ver Trofeo&nbsp;El trabajo honra al mercenario&nbsp;</p><p>60- Desenterrar el tesoro de los chocobos en la Zona de los Pastizales.</p><p>61- Desenterrar el tesoro de los chocobos en la Región de Junon.</p><p>62- Desenterrar el tesoro de los chocobos en Corel.</p><p>63- Desenterrar el tesoro de los chocobos en la selva de Gongaga.</p><p>64- Desenterrar el tesoro de los chocobos en Cañón Cosmo.</p><p>65- Desenterrar el tesoro de los chocobos en la Región de Nibel.</p><p>66- Completar todos los informes Moguri. Ver Trofeo&nbsp;Amigo de los moguris&nbsp;</p><p>67- Reclutar a las 10 infanterías de la Séptima Compañía durante el desfile del Capítulo 4. Ver Trofeo&nbsp;Séptima Compañía, ¡firmes!&nbsp;</p><p>68- Romper 10 cajas con Cait Sith en el `minijuego del ascensor` en el Capítulo 11.</p><p>69 al 87- Todos estos premios se compran en las tiendas de Gold Saucer. Varios de ellos no aparecerán disponibles hasta que no superes los minijuegos de Gold Saucer en su totalidad.</p><p>88- Durante el reclutamiento de infanterías, a uno de los grupos de infantería tendrás que sacarle una foto junto a una figura de cartón de Rufus. Saca la foto cuando la retícula esté verde para ganar el premio.</p><p><br></p><p>Una vez hayas logrado la titánica tarea de reunir todos los premios, habla con Johhny, mira la divertidísima escena y conseguirás el trofeo. Por mera curiosidad, abre el cofre junto a él y bueno... que si logras sacar un rango S en ese `premio` avísame, porque te haré una estatua del material que tú quieras.​</p>', ''),
	(1353, 32, 'Héroe no hay más que uno', 'Por haber vencido a Sefirot en el combate 3D.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/555b3gb8.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Como consejo inicial antes de entrar con este minijuego; respira. Es un sistema que funciona. Relájate durante un par de minutos para limpiar tu mente antes de empezar.</p><p>El procedimiento es sencillo, pero exigente de ejecutar: con el stick izquierdo esquivas hacia el lado izquierdo y con el stick derecho, hacia el lado derecho. Con :l2: golpeas con tu brazo izquierdo y con el :r2:, con el derecho. La clave de esto es memorizarte las posturas de los enemigos para saber qué brazo van a utilizar para golpearte y hacia dónde tienes que esquivar. El problema vendrá cuando los enemigos más avanzados añadan golpes de gancho o descendentes a su lista de ataques, teniendo que pulsar el stick correspondiente hacia abajo o hacia arriba, respectivamente.</p><p>Para golpear tú no es tan simple, no vayas a lo loco porque no vas a dar ni una, ya te lo digo yo. Espérate a que el enemigo haga un gesto de cansancio o de burla y fíjate en qué brazo baja: si baja el izquierdo, tienes que golpear con :l2: y si es el derecho, con :r2:. Cuando el enemigo haga una oleada de puñetazos en modo "berserker" y los esquives todos, puedes golpear con cualquier brazo. Es un minijuego donde premia la paciencia y el saber mantener la cabeza fría, porque en el momento en que te desconcentres... te van a hacer un picasso en la cara bien guapo.</p><p>En cuanto a Sefirot, su combate se desbloquea en el Capítulo 12, cuando completes el Encargo 9: El Desafío del jugón. Su combate no se diferencia mucho de lo que has estado haciendo anteriormente. Cuando lo derrotes, conseguirás el trofeo.</p><p><br></p><p>NOTA: una gran ayuda para este minijuego es pausar con :options: cuando el enemigo esté haciendo una postura, para poder ver con toda tranquilidad lo que va a hacer y pulsar la dirección correcta mientras reanudas el juego,</p>', ''),
	(1354, 32, 'Con la música a todas partes', 'Por haber interpretado las seis partituras de la Sociedad para la Difusión del Piano y obtenido sus recompensas.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/0001dj15.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Se trata de conseguir como mínimo un rango A en las 6 partituras principales del juego. El minijuego del piano viene mercado en el mapa con el icono de... pues eso, un piano. Suele haber una partitura por cada región, siendo en la última región donde conseguirás la sexta (hay más de 6 partituras en el juego, pero para el platino solo necesitamos hacer las 6 primeras).</p>', ''),
	(1355, 32, 'Rey del ring', 'Por haber superado todos los desafíos de combate del Musculiseo.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/8jj46047.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Podrás comenzar los combates del Musculíseo desde el momento en que llegues a Gold Saucer. De todas formas, los combates no se desbloquearán en su totalidad hasta que no completes el juego. Por tanto, es mejor dejarlo para el post-game, subir al Nivel 70 y hacerlos todos sin ninguna dificultad. Puedes incluso bajar la dificultad a Fácil para hacerlo aún más... fácil, vaya.</p>', ''),
	(1356, 32, 'Rey del chocobódromo', 'Por haber ganado todas las carreras de chocobos.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/eee81g80.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Para este trofeo tendrás que ganar todas las carreras de las modalidades Básico, Avanzado y Copa de Oro del Gold Saucer. Aunque tendrás algunas carreras disponibles cuando llegues al Capítulo 8, no podrás completarlas todas hasta que no llegues a cierto punto del Capítulo 12. También, este trofeo forma parte de un encargo secundario, así que será un trofeo que conseguirás de camino al Trofeo&nbsp;El trabajo honra al mercenario&nbsp;.</p><p>Hay bastantes chocobos y armaduras a elegir para disputar las carreras, pero yo personalmente he hecho bastante cómodo el trofeo llevando siempre a Kuema con el set completo de mercenario. Por lo demás, las carreras no son más que ensayo y error, en cuanto te memorices los circuitos y sepas reaccionar ante los obstáculos, lo harás sin esforzarte demasiado.</p>', ''),
	(1357, 32, 'El trabajo honra al mercenario', 'Por haber completado todos los encargos.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/40061b45.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Deberás completar todos los encargos secundarios del juego, aquellos que aparecen indicados con una "!" en el mapeado. Algunas de estas misiones se pueden completar "a secas" y completar "bien". De la segunda forma, obtendremos las mejores recompensas, pero para conseguir el trofeo NO es necesario completarlas de la mejor forma, con completarlas "a secas" es suficiente.</p><p><br></p><p>Guía de encargos:​</p><p>Los encargos son las misiones secundarias de Final Fantasy VII Rebirth, con una estructura similar a la que tenían en su precuela, Final Fantasy VII Remake. Tendremos que completar todos para el trofeo</p><p>&nbsp;El trabajo honra al mercenario&nbsp;.</p><p><br></p><p>Existen dos formas de completarlos, de la forma correcta, con un icono de estrella amarillo, o mal. Lo ideal es completar todas bien para obtener la mayor recompensa posible. Esta guía es para conseguir el mejor final posible en cada encargo.</p><p><br></p><p>Si hacemos mal un encargo o no lo completamos, podremos realizarlo al terminar el juego con la opción de repetir capítulo, donde se nos preguntará si queremos Mantener los encargos completados, restablecer los encargos completados o reiniciar todos los encargos, donde aunque se reinicien se mantendrán completos los que ya hicimos.</p><p><br></p><p>En esta guía los encargos están ordenados según la primera vez que están disponibles, podemos seguir el orden o volver a ellos cuando queramos hasta el comienzo del Capítulo 13, ya sea de la trama o al repetir capítulos tras completar la trama.</p><p><br></p><p>Capítulo 2:</p><p><br></p><p>Encargo 1: Flores para una corona</p><p>Localización: Zona de pastizales - Rancho de Bill</p><p>En el diálogo con Cloe respondemos `Nosotros nos encargamos`. Vamos al punto marcado en el mapa y recogemos únicamente las flores rojas, blancas y amarillas. Se las damos a Cloe y misión completada.</p><p>Recompensa: + Afinidad con Aeris</p><p><br></p><p>Encargo 2: Carta en busca y captura</p><p>Localización: Kalm - Bar La Flecha Oxidada</p><p>Hablamos con Val, el camarero, para aceptar iniciar el encargo. Empezamos ganando una partida de cartas con Val.</p><p>Subimos por las escaleras a la zona noreste para hablar con Virgo y ganarle al juego de cartas.</p><p>Después nos dirigimos al este de Kalm, entramos en la casa y retamos al juego de cartas a Tauro. Regresamos al bar para terminar este encargo.</p><p>Recompensa: Carta nº 107 Chocobo y Moguri, + Afinidad con Tifa</p><p><br></p><p>Encargo 3: El sustento de Kalm</p><p>Localización: Kalm - Plaza central</p><p>Hablamos con el Alcalde de Kalm, nos dirigimos al Taller de tuberías de Mako al suroeste de Kalm para tener una conversación.</p><p>Tendremos que encontrar 3 chapas oxidadas y 5 clavos viejos, los cuales están indicados en el mapa, muy cerca del taller.</p><p>Al tener todas las entregamos y seguimos a la chica hasta la tubería, luchando tres veces por el camino. Regresamos con el alcalde para terminar.</p><p>Recompensa: 3.000g, + Afinidad con Barret.</p><p><br></p><p>Encargo 4: Ganado en peligro</p><p>Localización: Kalm - Tablón de encargos</p><p>Al aceptar el encargo nos dirigimos a Granja de Oliver al este de Kalm y hablamos con el granjero para aceptar eliminar a los monstruos.</p><p>Nos acercamos a investigar, subimos al chocobo y olfateamos pulsando Arriba en la cruceta para detectar el rastro a seguir, así cada vez que desaparezca, para llegar a la playa al oeste de la granja y tener que derrotar al Colmilludo Blanco y regresar a la granja para terminar el trabajo.</p><p>Recompensa: Aro alulante, + Afinidad con Red XIII</p><p><br></p><p>Encargo 5: A merced del viento</p><p>Localización: Kalm - Tablón de encargos (Al completar los otros 4)</p><p>Hablamos con Broden en la posada de Kalm y nos dirigimos a Molinos, al norte de Granja de Oliver, para hablar con Milud.</p><p>Tendremos que encontrar 5 Huesos de bestia, 1 Titanio de la pradera, 2 Minerales de hierro y una garra del Quetzal.</p><p>Todos son materiales comunes de la zona menos el último, ya que este se consigue únicamente en la Batida de Caza: `Un ave prehistórica` derrotando al Quetzal, ubicada al sureste del Taller de tuberías de mako.</p><p>Una vez tengamos los materiales, fabricamos el Engranaje del molino desde Síntesis y se lo entregamos a Milud. Volvemos a la pusada de Kalm para terminar este encargo.</p><p>Recompensa: Paño tempranero, + Afinidad con Red XIII</p><p><br></p><p>Capítulo 4:</p><p><br></p><p>Encargo 1: Vía de subsistencia</p><p>Localización: Región de Junon - Rancho de Gabon</p><p>Hablamos con el ranchero y aceptamos el encargo. Nos dirigimos al oeste a una zona con Chocobos donde debemos avanzar en sigilo.</p><p>Activamos la palanca y avanzamos junto a la máquina que se mueve delante del primer Chocobo. La segunda palanca hace venir una segunda máquina para escondernos y luego lanzar una piedra para volver a activar la palanca y avanzar escondidos.</p><p>Nos escondemos tras la tercera máquina y lanzamos una piedra a la palanca que hay mas adelante entre dos Chocobos a la derecha de Belén y avanzamos escondidos hasta que de la segunda curva, donde cambiamos de lado para que no nos vea otro Chocobo, después nos volvemos a esconder, ya de Belén, para colocarnos detrás y poder subirnos.</p><p>Ya sobre Belén, avanzamos al este de la granja, subiendo una pared al norte de la parada de Chocobo hasta llegar a la cabaña con una persona durmiendo, al que despertamos `sacudirle cuidadosamente`, obteniendo la Lista del carretero.</p><p>Los tres objetos de la lista están con referencia a la torre de brisa marina. Empezando al norte de donde encontramos al Chocobo Belén, usando el olfato al aparecer el circulo ? rojo. La siguiente algo mas al norte y el tercero al este del 2º entrando en una zona vallada bajo una plataforma gigante.</p><p>Regresamos a la Cabaña del carretero al tener los tres, se los entregamos y le pedimos la pieza del carro. Regresamos con Gabon en su rancho para terminar este encargo.</p><p>Recompensa: Chocobotaxi (Viaje entre regiones), 10 cedros de cóndores, 10 robles añejos, Brazalete real, + Afinidad con Aeris</p><p><br></p><p>(Avanzando en la trama)</p><p><br></p><p>Encargo 2: Amor de una madre</p><p>Localización: Región de Junon - Bajo Junon, frente al hostal</p><p>Hablamos con Ronda y aceptamos su encargo. Salimos al Almacén del pescador, a las afueras de Bajo Junon para interactuar con Arenque y seguirle por un largo camino derrotando a varios enemigos, siempre cuidando que no dañen mucho a Arenque.</p><p>Al llegar al Colectivo Junon acabará este encargo.</p><p>Recompensa: 3 fragmentos de mineral de mitrilo, 2 rubies, Manual de tiro (vol. 1) para Barret. + Afinidad con Barret.</p><p><br></p><p>Encargo 4: Negocios en el faro</p><p>Localización: Región de Junon - Colectivo Junon</p><p>Continuación del encargo dos, seguimos a Toby y nos dirigimos al faro del cabo, al sur.</p><p>Subimos la escalera y en la parte de arriba con la zona de descanso encontramos a... una cara conocida. Entonces aparecerán unos monstruos que tendremos que derrotar.</p><p>Este combate será duro salvo que nos preparemos muy bien para realizar ataques mágicos, especialmente con Aeris, ya que si vamos solo a golpes físicos lo pasaremos realmente mal.</p><p>Una vez derrotados acabará este encargo.</p><p>Recompensa: Equipamiento para Chocobos: Gorra de mercenario, faldón de mercenario, espinilleras de mercenario, + Afinidad con Red XIII</p><p><br></p><p>Encargo 3: ¡Croad más alto!</p><p>Localización: Región de Junon - Bajo Junon, Tablero de encargos.</p><p>Aceptamos el encargo, bajamos al puerto y nos movemos por la playa hasta la zona sur donde veremos unas ranas, después tendremos que tener un combate contra unos enemigos, pero convertidos en rana para dificultadlo un poco.</p><p>Una vez derrotados hablamos con los niños para jugar a El salto de la rana, intentando aguantar el máximo tiempo posible para mayor recompensa, aunque podremos repetirlo tras el encargo.</p><p>Recompensa: X3 anillo de rana, El salto de la rana desbloqueado, + Afinidad con Tifa</p><p><br></p><p>Encargo 5: Arriba, a lo lejos</p><p>Localización: Región de Junon - Colectivo Junon, Tablero de encargos.</p><p>Nos dirigimos al oeste de Colectivo Junon tras aceptar el encargo, subimos hasta el campamento y hablamos con Colin.</p><p>Nos dirigimos al oeste a Bosque del Cazador, donde habrá una vaca a la que acercarnos en sigilo. Al huir usamos el Chocobo para olfatear su rastro, salvarla de unos enemigos y de nuevo tener que olfatear para encontrarla y derrotar al enemigo.</p><p>Ahora es muy importante al tener que elegir entre la vaca y el monstruo elegir la vaca para completar correctamente el encargo.</p><p>Regresamos a Colina del Cóndor para entregar la carne de vaca y terminar el encargo.</p><p>Recompensa: Foto nítida del cóndor, Materia supresora, + Afinidad con Tifa</p><p><br></p><p>Capítulo 7:</p><p><br></p><p>Encargo 1: El Vistamar a toda vela</p><p>Localización: Costa del sol - Distrito de reurbanización</p><p>Hablamos con Johnny, después salimos al oeste de Costa del Sol para encontrar unos clones de Johnny.</p><p>Ahora tendremos que localizar todas las tirolinas de la zona, mirando en sitios altos y subiendo a ellos, ya que cada uno tendrá un objeto. Necesitaremos mínimo 4 pero debemos conseguir todos para completar bien esta misión.</p><p>Al tener todos se los entregamos a los Johnnys y los entregamos, apareciendo tres estrellas junto a la respuesta. Después nos dirigimos a la fábrica abandonada donde nos pedirán que fabriquemos Válvula de caldero, una receta que conseguiremos oliendo con el Chocobo dentro de la propia fábrica, con materiales de los alrededores. Al crearla se la entregamos a Johnny, a uno de ellos.</p><p>La siguiente parte de la misión no se puede hacer hasta el capítulo 9.</p><p>Ya en el Capítulo 9 tendremos que hacer todas las batidas de caza de la zona hasta desbloquear el combate contra el jefe secreto, el Rey Tomberi. En este combate debemos tener un personaje con la materia de hurto equipada, dañar al Tomberi de forma continuada hasta que quede fatigado y pierda la corona, y entonces usar la habilidad de Robar sobre la corona para quitársela y después derrotarlo, para así obtener la corona intacta y poder completar bien este encargo.</p><p>Al terminar el combate y tener la corona en nuestro poder regresamos a frontera del desierto para entregársela y ya para terminar a Costa del Sol a El vistamar de Johnny.</p><p>Recompensa: Mejora de El Vistamar de Johnny, Carta nº 134 de los Johnnies, Vistamar de Johnny viaje rápido, + Afinidad con Yuffie, Colección de Johnny</p><p><br></p><p><br></p><p>Encargo 2: Cita en Costa del Sol</p><p>Localización: Costa del sol - Playa de Costa del sol</p><p>Hablamos con las chicas sobre el escenario. Tras aceptar el encargo nos dirigimos a Carrera Salvaje donde jugamos la versión contrarreloj de Carrera salvaje, donde debemos meter cada bola numerada en la portería de su color tal como se indica arriba a la derecha, preferiblemente en menos de 3 minutos. Con cuidado al final porque las porterías se taparán con obstáculos, siendo mas fácil dar un remate para arriba para saltarse los obstáculos.</p><p>Nos dirigimos a Piratas al Abordaje, esta vez jugamos la modalidad Barco fantasma, donde es recomendable conseguir 18.000 puntos, siempre evitando fallar demasiado para no perder muchos puntos.</p><p>Nos dirigimos a la salida de Costa del Sol a hablar con Yorda, nos subimos al Chocobo y avanzamos al suroeste a playa de las Conchas para olfatear con el Chocobo en busca de tres conchas.</p><p>Al tener las tres regresamos a la Tienda de alquiler de chocobos. Le tenemos que entregar la concha gigante, la de tres estrellas.</p><p>Nos dirigimos a la zona del evento para terminar el encargo.</p><p>Recompensa: Megalopulsera, 2 Ultrapociones mixtas, Brazalete abismal, X2 Ultrapoción vaporizada, Bono de alquiler de Chocobo, Equipamiento para Chocobos: Visera tropical, chal tropical, par de sandalias tropicales, El arte de la espada (vol. 2) para Cloud, + Afinidad con Aeris, Encargo 3 desbloqueado</p><p><br></p><p>Encargo 3: ¡Maravimusculoso!</p><p>Localización: Costa del sol - Tablón de encargos</p><p>Al completar el encargo 2, aceptamos el encargo en el tablón. Nos dirigimos a Concentración de entrenamiento, al oeste de Costa del Sol para hablar con Jules. Respondemos `La fuerza de voluntad` y aceptamos derrotar a los monstruos de alrededor de la zona, siendo cuatro grupos de enemigos.</p><p>Al derrotarlos hablamos de nuevo con Jules y aceptamos el duelo de abdominales... si, toca revivir traumas del pasado.</p><p>Ganamos al minijuego para terminar este encargo.</p><p>Recompensa: X3 Batido veloz, desbloqueo de minijuego de Abdominales, + Afinidad con Tifa.</p><p><br></p><p>(avanzando en la trama)</p><p><br></p><p>Encargo 4: Secuestro a un túnica negra</p><p>Localización: Corel norte - Clínica</p><p>Aceptamos el encargo en el tablón o hablamos con Sheiran en la clínica, seleccionamos inspeccionar la carta y seguimos a Red XIII, derrotando enemigos. Cuando Red XIII se pare, avanzamos hasta el Chocobo, donde sacaremos la linterna para enfocar al rastro y seguirlo. Aunque el recorrido es lineal, si recomiendo explorar todo ya que veremos algún arma y materia por la cueva.</p><p>Al llegar a la puerta cerrada continuamos el recorrido por la derecha, activamos la palanca y nos balanceamos cruzando por el techo hasta la zona de descanso al otro lado de la zona grande, escalamos por la pared hasta el interruptor y entramos. Al ver una escena desconfiamos y luchamos contra un enemigo fuerte. Tras un dialogo terminará este encargo.</p><p>Recompensa: La leyenda del guerrero rojizo (vol. 2) para Red, + Afinidad con Red XIII.</p><p><br></p><p>Capítulo 9:</p><p><br></p><p>Nota: Ahora podremos terminar el encargo 1 del capítulo 7.</p><p><br></p><p>Encargo 5: ¿Dónde está Piquito?</p><p>Localización: Región de Corel - Corel Norte</p><p>Hablamos con los niños y aceptamos el encargo. Tendremos que construir en Síntesis tres Trampa para pájaros, que aprenderemos en la zona de informe de excavación 2. Fabricamos tres y las colocamos en las zonas marcadas.</p><p>Al colocar todas regresamos a la trampa marcada y luchamos contra unos monstruos, así dos veces, después en la tercera habrá que derrotar a un Bom gigante. Regresamos a Coren para hablar con los niños y terminar el encargo.</p><p>Recompensa: Materia de nivel extra, Afinidad con Barret</p><p><br></p><p>Encargo 1: Adiós a las armas</p><p>Localización: Región de Gongaga - Taller de Izo</p><p>Entramos al taller, al sureste de la Costa de Gongaga, entre la selva. Se iniciará el encargo donde tendremos que buscar materiales para el arma de Barret, concretamente en Almacén de Izo al sur, donde abrimos el cofre con las fotografías.</p><p>En la 1ª tomamos de referencia el dibujo del perro en la pared para avanzar hacia el noroeste hasta ver un campamento, después seguimos hacia el oeste según la foto 2. Pasamos tras la roca con el agujero en el centro hacia el suroeste según la foto 3 y giramos a la derecha (norte). Al ver la columna de la foto 4 giramos a la izquierda al oeste y al ver el arbol grande con muchas ramas tendremos un combate sorpresa contra unos enemigos. Miramos junto a la pared a la derecha las rocas azules, recogemos 8, 2 abajo y 6 subiendo la cuerda.</p><p>Al tener todos los minerales de dragonita regresamos con Izo a su taller para entregar los 8 minerales y terminar el encargo.</p><p>Recompensa: Fafnir, + Afinidad con Barret.</p><p><br></p><p>Encargo 2: ¡Sí, maestra!</p><p>Localización: Región de Gongaga - Aldea de Gongaga</p><p>Aceptamos el encargo en el tablón o tomamos la salida sureste de la aldea para ver al objetivo, el miembro de la brigada juvenil.</p><p>Tendremos que rechazar el encargo, pero luego seguir a Sotetsu y hablar con él. Tendremos que cumplir tres objetivos, el de la fatiga con un hechizo de hielo da, después esperamos a que Sotetsu de 3 golpes y derribamos a los enemigos. Si fallamos podemos repetir el combate antes de avanzar.</p><p>Para el 2º combate debemos realizar fatiga dos veces, por ejemplo hielo a las dos ranas, después dejar vulnerable a algún enemigo, por ejemplo con Carga perforante de Cloud, y ganar sin que Sotetsu quede fuera de combate.</p><p>En el 3º a dejar vulnerable a dos enemigos, abusando de nuevo de la carga perforante, derrotando a los 4 en 2 minutos, cosa no muy complicada.</p><p>Continuamos hasta que pare a descansar y tendremos un 4º y último combate algo mas duro donde solo tendremos que ganar sin que Sotetsu caiga.</p><p>Regresamos a la aldea para tener un dialogo final y terminar este encargo.</p><p>Recompensa: El legado de los ninjas (Vol. 4) para Yuffie, + Afinidad con Yuffie</p><p><br></p><p>Encargo 3: Gallinas escapistas</p><p>Localización: Región de Gongaga - Aldea de Gongaga</p><p>Hablamos con la mujer del gallinero tras Librería Magnata y aceptamos el encargo de encontrar las cuatro gallinas.</p><p>Seguimos a Red XIII y usamos la lata como reclamo para atraer a la gallina hacia su dueña usando L2 para atraer la lata y que la gallina la siga.</p><p>Repetimos con las otras tres gallinas, esta vez desde mas lejos y teniendo en cuenta usarlo cuando tengan un ! y no un ? encima, con cuidado de cuando van corriendo al objetivo. Si huyen de vuelta se los lanzamos rápido para no perder mucha distancia.</p><p>En la cuarta gallina tendremos un combate contra un enemigo fuerte, y por suerte no habrá que entregarla tras ese combate, teniendo que volver directamente al gallinero</p><p>Recompensa: Talismán de la fortuna, + Afinidad con Red XIII</p><p><br></p><p>Encargo 4: Sin armonía no hay tutía</p><p>Localización: Región de Gongaga - Aldea de Gongaga</p><p>Entramos en la casa de Cissnei para iniciar el encargo, y al norte de la casa veremos al vendedor, que es bastante mas adorable de lo esperado.</p><p>Seguimos a Goya por la selva hasta el Huerto de Torgan y después lo seguimos de nuevo, teniendo que luchar contra monstruos entre medias. Al llegar miramos en la nota la sal que mas se parece, que es la rosa grande al fondo, después buscamos por la zona otras dos que sean igual.</p><p>Viajamos a Colina de Magon al sur de la aldea y con el olfato del Chocobo buscamos las setas, seguimos el rastro y las recogemos.</p><p>Tendremos que ver en cual de las direcciones se dobla mas, media o menos para determinar el orden, pudiendo cometer varios errores pero siendo recomendable guardar antes por si la dañamos, estando atentos y marcando con R2 antes de pulsar L2+R2 para conseguirla. Repetimos dos veces mas.</p><p>Al tener todas regresamos a la casa de Cissnei, hablamos con ella y le entregamos los ingredientes (3 estrellas si lo hicimos bien).</p><p>Recompensa: Par de pendientes de materia energética + Afinidad con Aeris</p><p><br></p><p>Capítulo 10:</p><p><br></p><p>Encargo 1: Chocobo volador</p><p>Localización: Región de Cañón Cosmo - Rancho de Kinama</p><p>Hablamos con Kinama, después nos dirigimos al norte para encontrar otra zona de Chocobos donde avanzar en sigilo hasta el Chocobo de diferente color.</p><p>Empujamos el carro desde atrás y si nos ve el 2º Chocobo cambiamos de lado y empujamos desde el otro lado hacia atrás, hasta la palanca para cambiar las vías y seguir empujando hacia arriba, atentos al tercer Chocobo, cuando mire para atrás. Lo empujamos hasta antes del cruce de vías y la palanca y usamos una piedra para distraer al Chocobo y activar la palanca. Lanzamos una roca al 5º Chocobo para distraerlo y avanzar hasta el Chocobo especial.</p><p>Una vez tengamos el Chocobo nos dirigimos al circuito al sur a hablar con Cicica. Conseguimos suficientes puntos para completarlo y desbloquearemos el 2º circuito, al este de Rancho de Kimama.</p><p>Al llegar al circuito agotamos conversación con Cicica y hacemos el 2º circuito con al menos puntuación básica, después pasamos al 3º, al sur de Rancho de Kimama, terminando este encargo.</p><p>Recompensa: La leyenda del guerrero rojizo (vol. 6), las recompensas de los tres circuitos, + Afinidad con Yuffie.</p><p><br></p><p>(Avanzando en la trama)</p><p><br></p><p>Encargo 2: Augurios de una catástrofe</p><p>Localización: Región de Cañón Cosmo - Cañón Cosmo - Seminario de astrobiología</p><p>Encontraremos a César al fondo de la sala de reuniones, junto al telescopio, que nos enviará este encargo.</p><p>Tendremos que dirigirnos a tres puntos del mapa para hacer fotografías, el 1º desde el Aeródromo, nos dirigimos al este y rodeamos hacia el sur subiendo por las rocas, donde tendremos que luchar contra un enemigo fuerte para después hacer la foto. Debe ser igual a la nota de referencia y con un zoom igual, que es 80% o superior, que quede marcado en verde.</p><p>El segundo se encuentra a la derecha del anterior en el mapa, por la zona baja del mapa, tras una parada de Chocobotaxi y cerca de la batida de caza 1, subimos las escaleras tras la parada para llegar al punto de la foto donde habrá otro enemigo igual para derrotar, esta vez acompañado. La foto como antes, buscamos +80% de similitud con la nota.</p><p>El siguiente se encuentra al noreste, cerca de la Batida de caza VI, subiendo las escaleras y un ventilador que impuse al Chocobo hasta la cima, donde habrá enemigo a derrotar y lugar de fotografía y la realizamos con puntuación de +80% también.</p><p>Al tener todas regresamos a Cañón Cosmo, al Seminario de astrobiología a entregar las fotografías a César.</p><p>Recompensa: Baraja de cartas del Tarot, + Afinidad con Aeris.</p><p><br></p><p>Encargo 3: El latir del planeta</p><p>Localización: Región de Cañón Cosmo - Cañón Cosmo - Observatorio de Cañón Cosmo.</p><p>Dentro del observatorio hablamos con Bugenhagen. Tendremos que ir a una serie de localizaciones no marcadas, que son esas zonas valladas cerradas que seguramente habremos visto explorando y no sabiamos como acceder.</p><p>La primera se encuentra al sur de Cañón Cosmo, rodeando la roca desde abajo hacia el este, al interactuar con la puerta aparecerá Bugenhagen y usará la llave para poder acceder a esta zona y las notas para las zonas 2 y 3.</p><p>Ambas zonas se encuentran al sureste del aeródromo, pero en el suelo de la zona amplia desértica, donde habrá una parada de Chocobotaxi y el 2º objetivo al este subiendo por unas ruinas, donde unos enemigos están intentando dañar la valla, los derrotamos y al interactuar con la puerta nos la volverán a abrir.</p><p>La tercera se verá según salimos de la segunda, al norte en una cueva tapada con tablas de madera, nos acercamos a derrotar a los enemigos y nos abrirá la puerta para poder entrar también.</p><p>En el cuarto se nos dará la nota del revés, en realidad tendremos que ir al este de Informe de activación IV: La torre del circuito y salvar la valla del ataque de los monstruos nuevamente, para recibir el 5º informe.</p><p>En el 5º si nos fijamos aparecerá en el centro la cabaña Moguri con forma de seta, por lo que también está invertido y llegaremos desde la propia cabaña de Moguri en la zona sur del mapa, avanzando hacia el sur hasta ver la puerta, esta vez sin enemigos, pero como se intuye al ver una zona tan grande y vacía, habrá que pelear. Agotamos todas las preguntas y terminamos este encargo.</p><p>Recompensa: Secretos del porvenir (vol.4) para Cait Sith, + Afinidad con Red XIII</p><p><br></p><p>Encargo 4: Espectro errante</p><p>Localización: Región de Cañón Cosmo - Cañón Cosmo: Escalinata de los errantes</p><p>Hablamos en la entrada con el guardia del puente para iniciar este encargo.</p><p>Nos dirigimos al punto marcado al norte, desde la parte baja, pudiendo planear desde el otro lado del puente de la aldea con un Chocobo y llegar rápido allí. Derrotamos a los enemigos y avanzamos al siguiente para derrotar a mas enemigos y de nuevo repetimos proceso. El último jefe será un Apisonaratops, un enemigo bastante fuerte que es capaz de hacerse inmune a los ataques y repeler la magia, por lo que tendremos que quitarle la salud poco a poco y estar mas atentos a esquivar y curarnos, atacando cuando tengamos oportunidad, por ejemplo a distancia con Barret.</p><p>Al derrotarlo preguntamos sobre Seto, sobre la petición de los Gi y sobre la traición.</p><p>Recompensa: Amuleto de invocación, + Afinidad con Red XIII</p><p><br></p><p>Capítulo 11:</p><p><br></p><p>Encargo 1: Faena y doma de chocobo</p><p>Localización: Región de Nibel - Morada Chocobo</p><p>Nos acercamos a Billy para iniciar este encargo, decimos que es un genio y tendremos que atrapar al Chocobo Selena, que estaba al comienzo de la zona cerca del aeródromo y hasta es posible que lo tengamos ya.</p><p>Si no lo teníamos, para atraparlo hay que lanzarle fruta desde la zona de arriba y guiarlo entre las plantas que se van desinflando, con cuidado de que al inflarse no lo dañen, poco a poco hacia la izquierda hasta llegar a la zona asequible donde subirse sobre él.</p><p>Al tenerlo e informar al domador debemos recoger 30 hierbas chocoberas, que son las que están levitando en el aire y se recogen al impulsarnos sobre el chocobo con L2.</p><p>Por último habrá que hacer una carrera de chocobos sobre el nuevo Chocobo, después preguntar las tres opciones antes de terminar el encargo.</p><p>Recompensa: Brazalete Chocobo, + Afinidad con Yuffie</p><p><br></p><p>(Tras avanzar en la trama)</p><p><br></p><p>Encargo 2: Angelito minino</p><p>Localización: Región de Nibel - Nibelheim: Restaurante</p><p>Entramos en el Restaurante y hablamos con la chef. Aceptamos ir a buscar su gato.</p><p>Salimos hacia el monte Nibel, al este de la zona para encontrar una zona varios gatos donde habrá que luchar, no contra los gatos precisamente. Después seguimos al gato por la montaña peleando con mas enemigos, entre ellos una abeja reina bastante fuerte que invoca a mas abejas.</p><p>Después tendremos que avanzar a un ritmo de trote hacia Nibelheim mientras nos siguen los gatos, al llegar nos dirigimos a la plaza y hablamos con Tifa.</p><p>Subimos a la segunda planta del Centro de para tener que tocar el piano consiguiendo una puntuación alta, preferiblemente A.</p><p>Recompensa: Aerith`s Theme, Artes marciales legendarias (vol. 5) para Tifa, + Afinidad con Tifa</p><p><br></p><p>Capítulo 12:</p><p><br></p><p>En este capítulo habrá que volver a las regiones anteriores a hacer encargos nuevos.</p><p><br></p><p>Encargo 6: Se buscan empleaos</p><p>Localización: Zona de pastizales - Kalm: Calle principal</p><p>Hablamos con los bandidos y les seguimos el juego respondiendo Cloud Strife, Ex-Soldado, No dejaré monstruo vivo.</p><p>Salimos de Kalm hacia la autopista al oeste para derrotar enemigos, en dos tandas, primero lobos y después maleantes.</p><p>Recompensa: Manual de tiro (Vol. 6) para Barret, + Afinidad con Barret</p><p><br></p><p><br></p><p>Encargo 6: Sin pegar ojo</p><p>Localización: Región de Junon - Bajo Junon</p><p>En el puerto veremos a los niños, que nos mandarán este encargo.</p><p>Tendremos que realizar el recorrido a delfín de la trama, con tiempo de entre 2:00 y menos de 1:40 para las mejores recompensas.</p><p>Recompensa: Elixir, Fragmento de mineral de planetita, 3 Orbes azabaches, + Afinidad con Yuffie</p><p><br></p><p>Encargo 7: Espécimen submarino</p><p>Localización: Región de Junon</p><p>Lo activamos en un Tablón de encargos o nos dirigimos al sur de Mina de mitrilo, a la costa, donde veremos varios infantes militares. Elegimos ayudarles y empezaremos el combate al acercarnos.</p><p>Tendremos que derrotar al Jinete infernal VR2, un enemigo que tampoco es excesivamente complicado a pesar de su imponente aspecto.</p><p>Ahora tendremos que subir al Chocobo e investigar el rastro para encontrar de nuevo a la criatura, pero esta vez teniendo que luchar contra otro enemigo.</p><p>Volvemos a seguir el rastro para volver a luchar contra el jinete infernal y ya si, completar el encargo tras preguntar todas las opciones.</p><p>Recompensa: El alma del planeta (vol. 6) para Aeris, + Afinidad con Aeris</p><p><br></p><p>Encargo 5: Laberinto sin salida.</p><p>Localización: Región de Gongaga - Aldea de Gongaga: Ladera de las fatsias</p><p>Hablamos con Maeve junto a la Chocobotienda, aceptamos y nos dirigimos a la playa al norte para empezar a hacer fotografías.</p><p>La idea es fotografiar a Red XIII en un punto acorde a lo que se nos ha pedido, que en resumen significa hacerle una foto con 100% y que a su vez nos salga un mensaje diciendo que si es la inspiración acorde, en este caso sobre una pequeña montaña.</p><p>La segunda localización es en el Reactor de mako de Gongaga, la foto es sobre la valla de entrada.</p><p>La tercera está en el Aeródromo de Gongaga, la foto correcta es sobre la torre de comunicaciones.</p><p>Regresamos a entregar las fotografías, y si son correctas terminaremos el encargo de la mejor forma posible.</p><p>Recompensa: Amuleto de luna nueva, + Afinidad con Barret</p><p><br></p><p>Encargo 6: Algo acecha en la maleza</p><p>Localización: Región de Gongaga - Aldea de Gongaga: Plaza de las violetas</p><p>Aceptamos el encargo en el tablón y veremos el objetivo cerca, iniciando una secuencia que activa el encargo.</p><p>Nos dirigimos a Torre de Observación al sur, subimos a la caja y buscamos zonas donde interactuar con Triangulo y luego dirigirnos a pie, hasta a tres localizaciones.</p><p>Recompensa: Secretos del porvenir (Vol 6) para Cait Sith. + Afinidad con Aeris.</p><p><br></p><p>Encargo 5: Amenaza bajo tierra</p><p>Localización: Región de Cañón Cosmo - Cañón cosmo: Valle</p><p>Aceptamos la misión en el tablón de encargos y hablamos con el viajero a mitad del valle de la región donde hay un coche aparcado. Preguntamos por las cuatro opciones.</p><p>Usando el sismógrafo, seguimos en la dirección donde se marquen círculos azules al caminar, hasta acercarnos con mas frecuencia y seguir a la criatura. Al 2º encuentro aparecerán otros enemigos, para después tener que seguir buscando.</p><p>En el tercer encuentro será el combate contra el gusano colosal, terminando el encargo al derrotarlo.</p><p>Recompensa: Materia de área, + Afinidad con Yuffie.</p><p><br></p><p>Encargo 3: Entre un llanto y una canción</p><p>Localización: Región de Nibel - Nibelheim: Ayuntamiento</p><p>Dentro del ayuntamiento hablamos con el responsable y le preguntamos sobre todas las opciones.</p><p>Nos dirigimos a la mansión Shinra para bajar al subsótano, después recibir la tarjeta para bajar al sótano.</p><p>Ya en el objetivo activamos el simulador para combatir en una serie de cuatro combates con distintos requisitos.</p><p>Al superar los cuatro combates VR avanzamos hasta el final de la sala para pelear contra otra criatura, resistente al físico pero débil al hielo.</p><p>Recompensa: Gigapoción, Éter seco, Omnipoción vaporizada, Materia potenciadora, El arte de la espada (vol. 6) para Cloud, nuevos desafíos del Simulador del laboratorio, + Afinidad con Barret.</p><p><br></p><p>Encargo 6: Aguas monstruosas</p><p>Localización: Región de Corel - Costa del Sol: Bar del sol</p><p>Tendremos el bar tras el tablón de encargos, así que o la aceptamos en el tablón o entramos directamente a hablar con el Alcalde Kapono a preguntarle todas las opciones posibles.</p><p>Nos dirigimos a la playa a un puesto donde encontraremos a Kyrie, que nos dará una receta para cebos legendarios que requieren tentáculos de Gran Molbol y Cuerno de galimatazo, los jefes secretos de batidas de caza en Gongaga y Cañón Cosmo, con los que tendremos que volver a luchar para obtenerlos.</p><p>Una vez creado el cebo entramos por la puerta de la playa de las Conchas a la playa oculta, colocar el cebo y derrotar a los Diablos marinos.</p><p>Regresamos con Kyrie y le decimos `Has delegado tu trabajo` y regresamos junto al Alcalde.</p><p>Recompensa: El legado de los ninjas (Vol. 6) para Yuffie + Afinidad con Yuffie</p><p><br></p><p>Encargo 7: La copa de Oro soñada</p><p>Localización: Región de Corel - Gold Saucer: Plaza Chocobo</p><p>Lo aceptamos en el Tablón de encargos o en Gold Saucer, en la zona de carreras de Chocobo.</p><p>Tendremos que ganar carreras hasta conseguir el rango de oro para poder participar en el torneo y ganar, preferiblemente ganando las tres carreras del campeonato.</p><p>Recompensa: + Afinidad con Tifa</p><p><br></p><p>Encargo 8: Arlequín el comodín</p><p>Localización: Región de Corel - Infrasaucer: Palestra de las bestias.</p><p>Encontramos a Leslie cerca de la entrada a la palestra de las bestias en Infrasaucer, le preguntamos todas las opciones y empezamos este encargo.</p><p>Tendremos que luchar en la arena unos desafíos especiales individuales con cada personaje, empezando por Yuffie, después Aeris, Barret, Tifa y para terminar Cloud.</p><p>Recompensa: Premio irresistible, Artes marciales legendarias (vol. 6) para Tifa, + Afinidad con Tifa.</p><p><br></p><p>(Tras avanzar en la trama)</p><p><br></p><p>Encargo 9: El Desafío del jugón</p><p>Localización: Región de Corel - Gold Saucer: Entrada</p><p>Aceptamos el encargo en el tablón de encargos de Costa del Sol y viajamos a Gold Saucer, al grupo de gente bailando en la entrada.</p><p>Tendremos que batir la puntuación en varios minijuegos o superarlo en duelos 1vs1.</p><p>El primero será la carrera de Chocobos, ganamos una carrera de 1vs1 a tres vueltas.</p><p>El segundo será el desafío de Locura sideral, 50.000 puntos para superarle.</p><p>El tercero será superarlo en el Musculiseo, compuesto de 5 combates bastante complicados, en especial el 2º que será contra 10 Tomberis. Aquí recomiendo tener equipado en los tres personajes el objeto fabricable Bufanda de rencor, para el que necesitaremos Manto del rey tomberi, derrotando al rey tomberi, el jefe secreto de caza en Región de Corel que derrotamos en el encargo "EL Vistamar a toda vela".</p><p>El cuarto minijuego será G-Bike, batiendo 32.000 puntos.</p><p>El último será una partida de cartas a Reina de sangre.</p><p>Cuando parece que hemos terminado habrá que derrotar al Sr. Jugón a un duelo de Brawler 3D. Para ganar medianamente fácil podemos pausar antes de que golpee y quitar la pausa mientras movemos el stick correspondiente repetidamente hacia el lado correcto.</p><p>Con todos los minijuegos superados, al fin podremos terminar este pesado encargo.</p><p>Recompensa: Materia de apuesta, Sepiroth como rival de Brawler 3D.</p><p>Ú</p>', ''),
	(1358, 32, 'Rebelde de altos vuelos', 'Por haber subido un personaje al nivel 70.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/6ddg53bd.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Acabarás el juego aproximadamente al Nivel 50, teniendo en cuenta que completas todas las secundarias y todo el contenido de los mundos abiertos. Realmente durante la primera partida no hay ningún método de farmeo que no sea una pérdida de tiempo, lo mejor es esperar a completar el juego, cargar el Capítulo 12 en Dificultad Difícil e irte a matar bichos a cualquier región. Prácticamente casi cada combate te subirá un nivel o te dejará cerca de subirlo, en función del tipo y la cantidad de enemigos a los que te enfrentes.</p>', ''),
	(1359, 32, 'Lucha sin tregua', 'Por haber infligido un 300 % de daño a un enemigo vulnerable.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/b88364eg.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Cuando aturdas a un enemigo, aparecerá un % bajo la barra de aturdimiento el cual puede aumentar con ciertos ataques, permitiendo que el enemigo sufra aún más daño por tus golpes mientras permanezca aturdido.</p><p>Hay algunos combates de jefe donde podemos conseguir esto, pero la forma más práctica es que repitas el combate contra la Invocación `Titán` y spammees el combo Técnica secreta + Puños de la Ira de Tifa en cuanto lo aturdas para que te dé tiempo a llegar al 300% de vulnerabilidad. Según el nivel que tengas, tendrás que elegir qué modalidad de Titán pelear.</p>', 'https://www.youtube.com/watch?v=gKzUUtXHPFM'),
	(1360, 32, 'Destreza inigualable', 'Por haber aprendido todas las habilidades de arma y todos los Límites, incluyendo los de los manuales de destreza.', 'BRONCE', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/gjj735g3.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Este será uno de los trofeos que conseguirás en la recta final del platino cuando hayas acabado la gran mayoría de actividades del mundo abierto. Lo que este trofeo te pide es obtener todas las habilidades propias de cada arma (con lo cual, necesitas sí o sí conseguir las 49 armas del juego, 7 por cada personaje), los límites finales de cada personaje y cada una de las habilidades de cada personaje, éstas son las habilidades que aparecen de color morado en el "tablero" de habilidades. Necesitarás una gran cantidad de PA para obtener todo y es por ello que necesitarás completar la gran mayoría del contenido del juego. Para aprender rápido cualquier habilidad de arma basta con que empieces un duelo contra cualquier invocación en el simulador de Chadley, uses varias veces la habilidad y salgas del combate cuando la hayas aprendido para cambiar de arma y repetir el proceso. No te preocupes, se guarda la mejora aunque te retires del combate.</p><p><br></p><p>Dejo aquí la lista de las armas junto con su localización:​</p><p><br></p><p>Cloud</p><ul><li>-Espada mortal: Por defecto.</li><li>-Espada distinguida: Capítulo 2 - En un cofre morado en el Ancladero del marjal. Se llega aquí como parte del objetivo principal.</li><li>-Espada rúnica: Capítulo 4 - Después del defile, tras una breve sección donde manejas a Yuffie y en el momento en que recuperes el control de Cloud, encontrarás el cofre con el arma junto al banco y las máquinas expendedoras.</li><li>-Devorafuerzas: Capítulo 8 - A la salida de la prisión de Corel, difícil que no veas el cofre.</li><li>-Espada de cristal: Capítulo 9 - En el reactor de Gongaga, tras pasar el banco y las máquinas expendedoras del inicio de la mazmorra, llegarás a una sala cuadrada con unos pocos enemigos. En cuanto los venzas, tendrás una salida norte (desde donde viniste) y una puerta entreabierta a tu derecha; sigue de frente y verás el cofre en el lado derecho.</li><li>-Espada volcánica: Capítulo 11 - En el Monte Nibel, cuando subas por una cuerda y asciendas la montaña siguiendo el camino principal, te toparás con un par de paredes con salientes amarillos y una plataforma entre los dos muros con el cofre. Ayúdate de las paredes para llegar a la plataforma y abrir el cofre.</li><li>-Perpetuador: Capítulo 13 - En el Templo de los Ancianos, cuando `rotes` la primera sala y avances hasta unas enredaderas que has de trepar, trépalas y sube todo recto al primer saliente para ver el cofre.</li></ul><p><br></p><p>Aerith</p><ul><li>-Bastón defensivo: Por defecto.</li><li>-Bastón milenario: Capítulo 2 - En un cofre a la derecha del mostrador de la tienda de Cloe en el Rancho de Billy.</li><li>-Bastón imperial: Capítulo 4 - En Bajo Junon. Cuando estés dentro de la posada y todos los compañeros se hayan distribuido en sus respectivas habitaciones, entra en la habitación de Aerith para abrir el cofre con el arma.</li><li>-Bastón arcano: Capítulo 7 - En Monte Corel. Cuando el grupo se divida, mira a la izquierda del banco y las máquinas expendedoras. Verás aquí el cofre con el bastón.</li><li>-Bastón sapiente: Capítulo 10 - Tras bajar de la barca siguiendo el objetivo principal de la Cueva de los Gi, abre el cofre junto al banco y las máquinas expendedoras.</li><li>-Bastón Prismático: Capítulo 12 - Supera los desafíos del Simulador Versus Shinra en la Mansión Shinra. Al hacerlo, abrirás una sala con un cofre que contiene el bastón.</li><li>-Gambanteinn: Capítulo 13 - Templo de los Ancianos. Cuando estés con el grupo capitaneado por Aerith y habilites un camino con sus mecánicas de magia, deberás bajar por unas escaleras oeste que llevan hacia el objetivo. Cuando bajes estas escaleras hasta abajo del todo, date la vuelta para ver el cofre.</li></ul><p><br></p><p>Tifa</p><ul><li>-Guantes de piel: Por defecto.</li><li>-Guantes sílfides: Capítulo 3 - En la Mina de Mitrilo. Cuando tu equipo se componga por Cloud, Aerith y Tifa, la verás mientras sigues tu objetivo principal ignorando unas escaleras a tu derecha.</li><li>-Nudilleras de káiser: Capítulo 5 - En la Bodega de carga 1, cuando empieces a llevar a Cloud y Tifa y elimines a un pequeño grupo de enemigos, verás el cofre en unas escaleritas a mano izquierda.</li><li>-Garras del dragón: Capítulo 8 - En el minijuego de Choque en el desierto, superando el modo Avanzado sacando un mínimo de 42.000 puntos.</li><li>-Colmillos de tigre: Capítulo 9 - Cuando te toque volver al reactor de Mako de Gongaga con el grupo de las chicas, llegarás a una piscina donde tendrás que usar la pistola de ganchos dos veces para subir al piso 2 de la Zona de control de potencia. Cuando subas, date la vuelta, deberías ver el cofre morado en el lado derecho, usa la pistola de ganchos en el saliente del fondo izquierda para llegar al cofre.</li><li>-Guantes de cristal: Capítulo 11 - Región de Nibel (camino hacia el reactor). Tras cruzar el puente nuevo, fíjate en el lado derecho del camino. Deberías topártelo casi sin querer realmente.</li><li>-Járngreipr: Capítulo 13 - Templo de los ancianos. Tras separarse los personajes en grupos de dos, cruzarás una torre circular y saldrás por el otro lado donde matarás a unos enemigos. Tras eliminarlos, salta el pequeño muro de roca y gira a la izquierda para abrir el cofre.</li></ul><p><br></p><p>Red XIII</p><ul><li>-Collar de mitrilo: Por defecto.</li><li>-Collar de la rebeldía: Capítulo 3 - Mina de Mitrilo. Cuando empieces a manejar a Barret, tienes el cofre con el arma donde el banco y las máquinas expendedoras.</li><li>-Collar de plata: Capítulo 6 - Queda el primero en el minijuego de Carrera Salvaje.</li><li>-Collar de amatista: Capítulo 7 - En la mina de carbón 1 de Corel del Norte. En cuanto llegues a la primera sala con dos salidas, ve por la derecha para encontrar el cofre. Te lo cruzarás seguramente mientras completas el Encargo 4: Secuestro a un túnica negra.</li><li>-Collar dorado: Capítulo 9 - En el reactor de Mako de Gongaga, durante la primera visita. Desde la sala del terminal para controlar el nivel del agua de la zona, tras haberlo operado, sube por la caja que arrastraste antes y métete en el conducto para regresar a la Zona de supervisión, donde verás el cofre sobre un contenedor. Ayúdate del contenedor pequeño para llegar al cofre y abrirlo.</li><li>-Collar mágico: Capítulo 10 - Cuando tengas que llevar unos objetos al círculo del anciano, trepa por la pared dirección sur y llegarás a una plataforma con el collar. Llévaselo al anciano y recibirás el arma.</li><li>-Brisingamen: Capítulo 13 - Templo de los ancianos. Cuando lleves por segunda vez al grupo de Aerith, avanza hasta el próximo cántaro vital y ve a la torre dirección oeste.</li></ul><p><br></p><p>Barret</p><ul><li>-Ametralladora: Por defecto.</li><li>-Cañón de gran calibre: Capítulo 2 - En un cofre cruzando el marjal, justo después de una pequeña cinemática donde ves a `alguien`.</li><li>-Acribilladora: Capítulo 7 - Monte Corel. Con Yuffie y el resto del grupo, al llegar al Área de supervisión de raíles (P1) en la Planta Baja de las Minas de carbón de Corel, sal al área exterior de la parte noreste para ver el cofre en el borde del acantilado.</li><li>-Ruleta de magma: Capítulo 8 - En el Desierto de Corel, en el pequeño camino que conecta con el desguace, a mano derecha justo antes del área circular.</li><li>-Fafnir: Capítulo 9 - Recompensa por completar el Encargo 1: Adiós a las armas.</li><li>-Bazuca maciza: Capítulo 10 - Cueva de los Gi. Tras abrir la puerta que se habilita al colocar las estatuillas de colores, seguirás avanzando y te toparás con un portón gigante que tienes que abrir arrastrando las cadenas. En vez de abrir la puerta, gírate y baja en dirección sur por los escombros, verás el cofre junto con unos enemigos alrededor.</li><li>-Alborotadora: Capítulo 13 - Templo de los ancianos. Cuando lleves al grupo de Cloud por segunda vez y arrastres una caja para cruzar un trecho, avanzarás y verás una breve secuencia. En vez de seguir el camino, entra a la torre junto a ti y abre el cofre.</li></ul><p><br></p><p>Yuffie</p><ul><li>-Shuriken cruzado: Por defecto.</li><li>-Daga giratoria: Por defecto.</li><li>-Víbora gemela: Capítulo 7 - Monte Corel. Absolutamente imposible que no la veas. Con Yuffie, cuando cruces por primera vez un trecho con el gancho, verás el cofre a tu derecha.</li><li>-Cazaáguilas: Capítulo 9 - Casa de Cissnei en la Aldea de Gongaga, verás el cofre al fondo a la izquierda.</li><li>-Luna oscura: Capítulo 10 - Recompensa por conseguir la máxima puntuación en el primer circuito de Bucle de Chocobo.</li><li>-Cruz de cristal: Capítulo 12 - Gold Saucer. Cuando hayas pasado toda la parte de citas y jefes y estés persiguiendo a cierto personaje, llegarás a una sala con un cartel en la entrada que pone `Authorized Personnel Only`. Verás el cofre en uno de los pasillos, justo antes de subir unas escaleras dirección oeste.</li><li>-Shuriken cortasombras: Capítulo 13 - Templo de los Ancianos. Tras acabar la `prueba` de Cloud y derrotar a un par de enemigos, baja las escaleras y encontrarás el cofre en una sala con dos direcciones.</li></ul><p><br></p><p>Cait Sith</p><ul><li>-Megáfono amarillo: Por defecto.</li><li>-Megáfono de hierro: Por defecto.</li><li>-Megáfono rojo: Capítulo 10 - A la venta en la armería de Cañón Cosmo.</li><li>-Megáfono de cristal: Capítulo 10 - Cañón Cosmo. Cuando salgas del observatorio siguiendo el objetivo principal, te saltará automáticamente un hallazgo que te llevará a un almacén lleno de materiales y cofres. En cuanto llegues a la puerta que tienes que abrir para salir al exterior, date la vuelta y sube las escaleras a tu derecha, aquí verás el cofre con el arma.</li><li>-Megáfono con eco: Capítulo 11 - A la venta en la tienda general de Nibelheim.</li><li>-Megáfono de oro: Capítulo 11 - Mansión Shinra. Cuando bajes al sótano y te enseñen la mecánica del lanzamiento de cajas, coge una de las cajas y estámpala contra el botón rojo de la pared dirección sureste. De esta forma, abrirás la celda que contiene el cofre con el arma.</li><li>-Gjallarhorn: Capítulo 11 - Entrega 45 manojos de hierba chocobera en la Chocobotienda a cambio del arma.</li></ul><p><br></p>', ''),
	(1361, 32, 'Héroe legendario', 'Por haber completado todos los capítulos de la historia en el nivel de dificultad difícil.', 'PLATA', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/dgg81b4b.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Esta dificultad se desbloqueará una vez finalices la historia principal en cualquier dificultad, pudiendo jugar los capítulos desde `Selección de capítulo` para mantener todo el equipamiento conseguido hasta ahora. Es recomendable dejar para el final esta dificultad, después de haber completado todo el contenido del juego incluído los desafíos de Cadley, para así poder contar con accesorios como el Crepúsculo universal, Lazos divinos y diferentes objetos que nos van a facilitar las peleas un montón. Incluso, puedes cargar el Capítulo 12/13 y completar las Batidas de caza especiales en Dificultad Difícil para desbloquear las piezas de Genji, que son otros accesorios que proporcionan ventajas impresionantes.</p><p><br></p><p>Como consejos generales frente a esta dificultad, asegúrate de que equipas a todos los personajes con materias curativas (curación, rezo y, muy especialmente, energéticas), protectoras, potenciadoras de atributos y algunas elementales combinadas con `Materia elemental` en la armadura, para poder tener absorción de ciertos elementos. Las de carga también son muy útiles si las tienes a su nivel máximo.</p><p>Algunos de los combates `peligrosos` que podemos encontrarnos en la partida:​</p><p><br></p><ul><li>Capítulo 8, Dyne: Aquí vas solo con Barret, fundamental que éste tenga como mínimo una materia protectora, energética y de carga. Al empezar el combate lanza Estallido y `Combustión interna`, después limítate a jugar a la defensiva lanzando `Barrera` y usando habilidades como `Agallas` y `Munición explosiva` cada poco rato. Si estás mal de vida, busca un hueco en la pelea y cúrate siempre con el `Chakhra`. Si vas con el Crepúsculo universal, lanza el límite cada vez que lo tengas.</li><li>Capítulo 12, Rufus: Es una pelea frustrante, pero se vuelve sencilla si vas con cuidado. Lleva a Cloud con una materia energética, temporal, potenciaataque, igneogélida + elemental en la armadura, de carga, guardia y guardia crítica. Si quieres acompañarlo con una materia protectora para tirar `Barrera` y una de curación para `Revitalia`, también está bien. Lleva el Crepúsculo universal para lanzar el límite siempre que puedas, pero usa siempre una `Bravura` antes de lanzarlo para hacer más daño. El procedimiento es el siguiente: empieza tirándote una `Prisa`, los ataques bloqueables de Rufus bloquéalos y, los que no se pueden bloquear, esquívalos. Mientras use Recarga, lanza rápidamente una `Espiral sesgadora` para fatigarlo y atácale durante unos pocos segundos, no te cebes mucho porque te contraatacará. En la segunda fase de la pelea, sigue el mismo procedimiento de bloquear, esquivar y atacar cuando recargue. Al perro simplemente esquívalo o úsalo para cargar BTC, con que muera simplemente Rufus ya se da el combate por finalizado. Si ves que va a lanzar disparos ígneos o gélidos, te curarás con ellos, por eso llevamos la Igneogélida con elemental. Lo importante de esta pelea es mantener las distancias y llegar siempre a las recargas de Rufus con mínimo una barra de BTC llena.</li><li>Capítulo 13, Dragón rojo: Esta pelea es una demostración de cuánta vitalidad tienen tus personajes. En mi caso llevaba a Cloud, Red XIII y Barret, todos con alguna materia vigorizante maximizada y mínimo uno de ellos con una protectora, curación y resucitadora + área. La pelea no supone ningún problema hasta que llegas a la segunda fase, donde te hará un horrible ataque que inunda todo el cuadrilátero de lava, sin haber posibilidad de evitarlo de forma natural. Aquí no queda otra que aguantar el ataque de lava, el problema es que es muy probable que la lava se cargue a todos tus personajes de golpe. Cuando vaya a lanzar el ataque, cura a todos los personajes con alguien que sea capaz de curar en área, Red XIII por ejemplo cura en área con `Protección heroica`, de lo contrario, limítate a usar una `Cura+` en área u `Oración`. Y con otro personaje que lleve una materia protectora, empieza a lanzar `Muro` sobre los personajes. Pero la cosa no acaba aquí, mientras estés encajando el daño de la lava, cura a todos los personajes de la forma que sea, es muy importante que seas veloz en este paso, porque de lo contrario no te dará tiempo a curarte y morirás de forma horrible. En caso de que alguien muera, usa `Lázaro` en área para revivir. No seas tacaño/a con la magia, si en este capítulo hay una pelea para gastar PM, es esta.</li></ul><p>Las demás peleas no es que merezcan mucha mención, dado que en este punto se da por hecho que has superado los desafíos de Chadley y sabes jugar perfectamente con una estrategia bien definida. Quizá tengas que cambiar equipamiento o materias según las circunstancias, pero no será un modo que te cueste especialmente.​</p>', ''),
	(1362, 32, 'La pesadilla de los píxeles', 'Por haber superado todos los desafíos del simulador de combate de Chadley.', 'PLATA', 0, 0, 0, 'https://m.exophase.com/psn/awards/s/j0015e41.png?5f889ea35a5e099f584c5f6f99c567e8', '<p>Uno de los trofeos que más pesadillas te van a producir de todo el juego. Los desafíos de Chadley los irás desbloqueando principalmente tras escanear a casi todas las especies de enemigos del juego o simplemente avanzando en la historia. La mayoría son bastante sencillos, pero los principales problemas los tendrás con los Desafíos `Épicos` y los Desafíos `Imbatibles`, siendo concretamente los desafíos `Líderes de otro mundo` y `Vínculo inquebrantable` los que disparan la dificultad de este platino. Estos dos desafíos te exigirán un conocimiento de las mecánicas del juego y una soltura a la hora de combatir prácticamente perfectos. Por supuesto, es obligatorio intentar estos desafíos estando al Nivel 70 y con las materias al nivel máximo.</p><p>Dejo aquí abajo un listado con las configuraciones recomendadas de cada personaje y unas pequeñas pinceladas para prepararte frente a los desafíos más duros. Obviamente dejo claro de entrada que hay muchas más combinaciones de materias, objetos y diferentes estrategias para afrontar los desafíos, incluso puede que tú te sientas más cómodo/a con otro tipo de set-up y este no se ajuste a tu forma de jugar, pero podemos garantizar que las configuraciones están probadas y tienen una alta garantía de éxito de cara a estos exigentes retos:</p><p><br></p><p>Para los desafíos `Imbatibles`:​</p><p><br></p><p>Cloud</p><ul><li>Arma: Espada distinguida.</li><li>MEJORAS: Carga BTC (2), ataque físico +20 (2).</li><li>Materias: Curación + área, vigorizante, etérea, resucitadora, fortalecedora.</li><li>INVOCACIÓN: Odín.</li><li>Armadura: Amuleto de los Cetra.</li><li>Materias: Igneogélida + elemental, robusta, iniciativa, carga, superación solidaria, guardia, encadenamiento.</li><li>Accesorio: Insignia bélica 2.0.</li></ul><p><br></p><p>Red XIII</p><ul><li>Arma: Brisingamen.</li><li>MEJORAS: Carga Venganza, Prisa, Estados beneficiosos otorgados (sube), ataque físico +20.</li><li>Materias: Protectora + área, resucitadora, vigorizante, etérea, robusta.</li><li>INVOCACIÓN: Alejandro.</li><li>Armadura: Aro de los Cetra.</li><li>Materias: Ígnea + elemental, iniciativa, superación cedida, guardia, curación, toxicopétrea, guardia crítica.</li><li>Accesorio: Bufanda del rencor.</li></ul><p><br></p><p>Barret</p><ul><li>Arma: Alborotadora.</li><li>MEJORAS: Carga BTC, ataque físico +20, carga inicial BTC y carga límite +10%.</li><li>Materias: Curación + área, ahorro mágico + resucitadora, etérea + vigorizante.</li><li>INVOCACIÓN: Gilgamesh.</li><li>Armadura: Amuleto de hades.</li><li>Materias: Ígnea + elemental, guardia critica, purificadora, carga, guardia, suerte.</li><li>Accesorio: Potenciador de límite.</li></ul><p><br></p><p>-Procedo a explicar los roles de cada personaje:</p><p><br></p><p>Red XIII: Usar `Venganza Glaciar` al principio de cada asalto y curar con su `Protección heroica`, a mejor efecto cuando más llena está su barra de venganza. No cargará nunca su límite, ya que este personaje está configurado para cargar las barras de límite de Cloud y Barret. También puedes aprovechar y usar sus habilidades de `Barrera`, `Barrera mágica` y `Muro` en área. Su `Rayo estelar` es muy efectivo contra los enemigos, así que no dudes en usarlo cuando lo veas conveniente.</p><p><br></p><p>Cloud: La idea es cargar siempre el límite de Cloud y lanzarlo cuando sea posible. Gracias a la habilidad `Superación solidaria` de Cloud, éste puede coger la barra de límite de Barret y juntarla con la suya propia para poder cargar su límite mucho antes. Cuando veas que las barras de Cloud y Barret suman una barra entera, usa la habilidad para cargar la barra de Cloud y lanzar su límite, que gracias al objeto que lleva equipado, lanzará siempre su límite "Toque final", el cual es el más poderoso de los suyos. Con las materias que lleva, cargará una barra de BTC al resto de compañeros cuando use dos habilidades BTC seguidas.</p><p><br></p><p>Barret: Usar `Estallido` y `Combustión interna` al principio de cada asalto, además de lanzar cada poco rato `Agallas` y `Munición explosiva` para asegurarte un buen daño a distancia con Barret durante un gran lapso de tiempo. También puedes usar `Lázaro` para resucitar a los compañeros que mueran y curar a todos los personajes. Contra los enemigos fatigados, su `Disparo ígneo` con dos barras cargadas de BTC es muy efectivo.</p><p><br></p><p>`Líderes de otro mundo` será el desafío más complicado de todos los Imbatibles. Cuando llegues a la ronda de Odín, evita lo máximo que puedas sus ataques y usa las habilidades ofensivas BTC de tus personajes para hacerle entrar rápidamente en fatiga. En ese momento, lanza con Barret un `Disparo ígneo` de dos barras de BTC y lo llevarás automáticamente a vulnerable. Contra Gilgamesh, lo más importante es que lleves una `Barrera` activa siempre, Red XIII las puede lanzar en área. Guarda el límite de Cloud cuando éste tire el `Escudo de Genji` para fatigarlo al momento. La última contra Sephiroth es fácil, pero tienes que sobrevivir al primer minuto de pelea, ya que te estará lanzando un ataque para aturdir a tus personajes y destrozarlos. Usa `Barrera` con Red XIII para amortiguar los ataques y cúrate en cuanto veas hueco. Superado el primer tramo de pelea donde dejará de usar ese ataque, lo demás es coser y cantar.</p><p><br></p><p>Para los Desafíos `Épicos`:​</p><p><br></p><p>Cloud</p><ul><li>Arma: Espada distinguida.</li><li>MEJORAS: Carga BTC (2), Ataque físico +20 (2).</li><li>Materias: Electroeléctrica + elemental, vigorizante, etérea, curación, fortalecedora.</li><li>INVOCACIÓN: Odín.</li><li>Armadura: Aro de los cetra.</li><li>Materias: Igneogélida + elemental, iniciativa, robusta, carga, disipadora, guardia, etérea.</li><li>Accesorio: Crepúsculo Universal.</li></ul><p><br></p><p>-En la segunda ronda cuando el lobo suelte el ataque cargado, usa el límite para evitar el ataque y darle un buen guarrazo al bicho, seguido de un par de `Cargas Perforantes` para que lo dejes vulnerable o muy cerca de vulnerable. En la tercera oleada, solo preocúpate de lanzar un `Disipabarreras` cuando el monstruo use el Escudo místico.</p><p><br></p><p>Barret</p><ul><li>Arma: Alborotadora.</li><li>MEJORAS: Carga BTC, Ataque físico +20, Carga Inicial BTC, Carga Límite +10%.</li><li>Materias: Igneogélida + elemental, energética, iniciativa, guardia, guardia crítica.</li><li>INVOCACIÓN: Fénix.</li><li>Armadura: Aro de los Cetra.</li><li>Materias: Veloz, fortalecedora, vigorizante, etérea, estratégica, protectora, temporal, carga.</li><li>Accesorio: Crepúsculo Universal.</li></ul><p><br></p><p>-El Adamantaimai es el mayor peligro de este desafío. Nada más empiece el combate, lanza una `Combustión interna` seguido de una `Prisa`. A continuación, lanza en cuanto puedas un Piro+ cuando hayas cargado una barra BTC y procede a dispararle hasta cargar las dos barras de BTC y soltar un `Disparo ígneo` a máxima potencia. Haz esto una vez más a base de Piro+ y `Disparo ígneo` de dos barras BTC para dejarlo vulnerable. Si el enemigo no se queda vulnerable rápidamente y se pone a lanzar los meteoritos, es misión imposible ya, dalo por perdido en ese caso. La clave está en mandarlo a vulnerabilidad lo más rápido que puedas a base de Piro+ para fatigar y `Disparo ígneo` de dos barras BTC para aturdir. Recuerda que puedes usar la carga con :l1: + :r1: para duplicar tu BTC. La última ronda es más jugar a la defensiva que otra cosa, disparando a una distancia prudencial, curándote y usando `Agallas` cada poco rato. Puedes lanzar tu invocación y el límite cada vez que lo tengas listo.</p><p><br></p><p>Aerith</p><ul><li>Arma: Gambanteinn.</li><li>MEJORAS: Ataque mágico +20, Carga BTC, Apoyo feérico duradero, PM max. +3.</li><li>Materias: Toxicopétrea + supresora, curación, temporal, carga e igneogélida.</li><li>INVOCACIÓN: Neo Bahamut.</li><li>Armadura: Aro de los Cetra.</li><li>Materias: Electroeléctrica + elemental, iniciativa, estratégica, guardia, vigorizante, taumatúrgica y etérea.</li><li>Accesorio: Crepúsculo Universal.</li></ul><p><br></p><p>-En la primera oleada es imprescindible que uses la Carga cuando llenes una barra BTC. En ese momento lanza un `Círculo mágico` y cárgate a un Cañón Aturdidor tirándole un Electro+. Sobrevive como puedas hasta que cargues otra barra BTC y derrota al otro Cañón Aturdidor con Electro+. Después despacha al resto de enemigos tranquilamente. Las siguientes rondas se resumen en usar Carga, plantar un `Círculo Planetario, usar `Carga Divina`, esperar a que la carga llegue al Nivel 2 y lanzarla contra los enemigos cuando estén vulnerables, causándoles un daño devastador. Recuerda que si te alejas mucho del círculo, puedes teletransportarte directamente hacia él pulsando :triangulo:.</p><p><br></p><p>Tifa</p><ul><li>Arma: Járngreipr</li><li>MEJORAS: Carga BTC, Potenciación de Zangan, Daño Límites +10% y Eficacia del arma +5%.</li><li>Materias: Igneogélida + elemental, curación, temporal, energética, vigorizante.</li><li>INVOCACIÓN: Gilgamesh.</li><li>Armadura: Aro de los Cetra.</li><li>Materias: Toxicopétrea + supresora, protectora, iniciativa, estratégica, etérea, guardia, guardia crítica.</li><li>Accesorio: Crepúsculo Universal.</li></ul><p><br></p><p>-Uno de los mayores peligros es El Niño G de la tercera oleada. Lo recomendable es atacarle cuando esquives sus ataques `Golpe de duende` y `Almádena`, ya que se fatigará si no te acierta con ellos. Si te golpea mucho, te lanzará un ataque que te mandará al otro barrio sí o sí. Cuando esté vulnerable, usa el combo `Técnica secreta` + `Puños de la Ira` hasta que se levante. En la última oleada contra el Galimatazo, ten siempre una barra de BTC disponible para cuando use su Escudo de Gorgona, en ese momento lanza `Vórtice de arrastre` para suprimir el escudo. Lo demás se reduce a curarte cuando veas hueco, tirar el límite cuando lo tengas y sacar a la invocación.</p><p><br></p><p>Red XIII</p><ul><li>Arma: Brisingamen.</li><li>MEJORAS: Ataque físico +20, Ataque básico +5%, Carga Venganza (2).</li><li>Materias: Igneogélida + elemental, temporal, purificadora, protectora, curación.</li><li>INVOCACIÓN: Odín.</li><li>Armadura: Aro de los Cetra.</li><li>Materias: Etérea, guardia, guardia crítica, energética, vigorizante, carga, iniciativa y estratégica.</li><li>Accesorio: Crepúsculo Universal.</li></ul><p><br></p><p>-Acostúmbrate a lanzar al inicio de cada oleada: Carga, `Prisa`, `Venganza glaciar` y el límite. Si se te da bien hacer parries con la Guardia Infranqueable, aprovéchalo, ya que si atacas justo despues de hacer el parry, harás buen daño y llenarás la barra de venganza. De lo contrario, simplemente bloquea normal los ataques de los enemigos. Ten cuidado con el Sapo gigante de la tercera oleada, aléjate de él y atácalo solo cuando se canse. Si salta y usa el Croac final, bloquéalo y atácale un poco, luego aléjate. Contra el Molbol de la última oleada, solo asegúrate de lanzar una `Resistencia` de cuando en cuando para eludir cualquier alteración de estado.</p><p><br></p><p>Yuffie</p><ul><li>Arma: Shuriken cortasombras.</li><li>MEJORAS: Prisa mágica, Carga BTC, Ataque básico +5%, Ataque físico +20%.</li><li>Materias: Curación, temporal, disipadora + supresora, protectora y vigorizante.</li><li>INVOCACIÓN: Alejandro.</li><li>Armadura: Aro de los Cetra.</li><li>Materias: Igneogélida + elemental, etérea, iniciativa, carga, guardia, estratégica, energética.</li><li>Accesorio: Crepúsculo Universal.</li></ul><p><br></p><p>-Yuffie se resume en usar al inicio de cada ronda: Carga, `Ninjutsu elemental` del elemento al que sea débil tu oponente y Desdoble Ninja. Después, carga las barras BTC lanzando el shuriken con :triangulo: y atacando con :cuadrado: sin recuperar el shuriken. Es decir, lanzando ataques mágicos. Lanza un `Exorcismo` y simplemente ponte a spammear `Revancha Sorpresa` hasta que el Exorcismo se cargue al Nivel 3. Resérvate este ataque para los enemigos más tochos o para momentos donde te veas con problemas. Recuerda que el `Exorcismo` será más poderoso si es del elemento al que es débil el monstruo al que vas a lanzárselo. El clon se irá al poco rato, así que no te olvides de usar `Desdoble Ninja` cada X tiempo. Lo único a lo que tienes que prestar atención es al Rey Zu de la última oleada: cuando use Colofón, concéntrate en destruir sus alas antes de que lance el ataque. Si lo lanza, se acabó todo.</p><p><br></p><p>Cait Sith</p><ul><li>Arma: Megáfono de oro.</li><li>MEJORAS: Ataque contra partes fracturables, Carga BTC, Eficacia del arma +5%, Luchador Moguri.</li><li>Materias: Igenogélida + elemental, curación, temporal, protectora y carga.</li><li>INVOCACIÓN: Fénix.</li><li>Armadura: Aro de los Cetra.</li><li>Materias: Energética, vigorizante, tóxicopétrea + supresora, etérea, guardia, iniciativa y estratégica.</li><li>Accesorio: Crepúsculo Universal.</li></ul><p><br></p><p>-Empieza cada oleada lanzando: Carga, `Prisa`, `Moguri al rescate` y lanza el límite. Después, baja del moguri y aléjate de los enemigos, deja siempre que el moguri se pegue con ellos. Tú tan solo tienes que atacar disparando (esquivar con :circulo: + pulsar :cuadrado:) para cargar la barra BTC y lanzar siempre `Tiro al azar`, además de usar `Moguri al rescate` cuando éste se vaya, es importantísimo que siempre esté el moguri en el campo para atraer la atención de los enemigos. Cuando dejes vulnerable a un enemigo, usa `Puñetazo moguri` y el límite cuando no tengas BTC para usar el puñetazo. Presta mucha atención al Mentalis de la última oleada y a su Rayo pavoroso, que es casi insta-kill. Intenta alejarte siempre de él. Cuando vaya a usar la Descarga mental, escóndete en las rocas. Sobre todo son combates para jugar defensivo con el moguri haciendo de señuelo y tú atacando a distancia.</p><p><br></p><p>Vínculo inquebrantable:</p><p><br></p><p>Cloud</p><ul><li>Arma: Espada distinguida.</li><li>MEJORAS: Carga BTC (2), Ataque físico +20 (2).</li><li>Materias: Reanimadora + ahorro mágico, curación + área, resucitadora, estratégica.</li><li>INVOCACIÓN: Fénix.</li><li>Armadura: Aro de los cetra.</li><li>Materias: Igneogélida + elemental, temporal + área, encadenamiento, vigorizante, guardia, etérea.</li><li>Accesorio: Crepúsculo Universal.</li></ul><p><br></p><p>-Empieza cada oleada lanzando una `Bravura` con Zack sobre Cloud y lanza el límite. Usa una `Prisa` con Cloud y empieza a pelear, lo más importante de todo es que los dos personajes vayan sumando acciones BTC continuamente para así poder lanzar siempre que puedas el ataque conjunto de los dos, el cual hará que Zack tenga magia infinita durante un rato (la cual puedes aprovechar para curarte o bufarte) y Cloud suba un nivel su límite. Es muy, pero que muy ideal, que Cloud llegue lo más pronto posible a su máximo límite.</p><p><br></p><p>-Contra Fénix, Cloud será invencible, pero Zack morirá a partir de cierto momento siempre. Tan solo revívelo justo antes de darle el golpe de gracia a Fénix. Contra Alejandro tienes que intentar llegar al límite final de Cloud antes de mandarle a vulnerable la primera vez, así puedes lanzar una Bravura y el límite final cuando consigas mandarle a vulnerable, matándolo o dejándolo tibio muy cerca de morir, recuerda concentrarte en sus brazos siempre y lanza `Muro` si ves que vas a comerte el Veredicto final. Contra Neo Bahamut, ve a muerte a por sus alas cuando se ponga a hacer la Carga de partículas. Si ves que no hay manera de evitar su Gigafulgor, lanza `Auto Lázaro` sobre Cloud. Contra Odín, mantente alejado y usa habilidades BTC contra él solo cuando veas que es seguro. Cuando le asestes varias habilidades BTC seguidas entrará en fatiga, lanza un par de `Cargas perforantes` para terminar de dejarlo vulnerable y dale con todo. Lanza la invocación cuando la tengas lista y así podrás lanzar `Auto Lázaro`, también tienes otro con Cloud que deberías usar por si acaso.</p><p><br></p><p>Condición heroica:</p><p><br></p><p>-Usa exactamente la misma configuración y estrategia que en el desafío anterior, solo que esta vez cuentas con Sephiroth el cual tiene `Auto Lázaro` en área y ataques devastadores. Además, también tendrá magia infinita si usas el ataque combinado de ambos, así que aprovéchalo al máximo. Este desafío en realidad es un regalo, lo más seguro es que te lo hagas a la primera. Solo lleva cuidado en las rondas del Rey Zu, al cual debes atacar a las alas cuando use Colofón, y la de Odin. Ataca a éste con cuidado de que no te golpee mucho y no lance el maldito Sable justiciero.</p>', ''),
	(1366, 31, 'Nativo de Raccoon City', 'Consigue todos los trofeos.', 'PLATINO', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/09f0b0d3-5112-4df2-82b1-d5accccb3a36.png', '<p>El anhelado platino, se obtiene al obtener todos los trofeos</p>', ''),
	(1367, 31, 'Bienvenidos a la Ciudad de los Muertos', 'Llega a la comisaría.', 'BRONCE', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/2505e982-e094-4b71-b6db-15eb684ef86b.png', '<p>Relacionado con la historia, imposible de perder.</p><p>Probablemente el primer trofeo que conseguirás. Te saltará apenas llegues a la estación de policía.</p>', ''),
	(1368, 31, 'Camino a la Diosa', 'Resuelve el rompecabezas de la estatua de la diosa.', 'BRONCE', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/ea2054b9-3c1f-40cf-9b63-e6b550173c3e.png', '<p>Relacionado con la historia, imposible de perder.</p><p>Cuando reunas los tres medallones de la estatua de la diosa y los pongas en su lugar, el trofeo será tuyo.</p>', ''),
	(1369, 31, 'Lluvia interminable', 'Escapa de la comisaría.', 'BRONCE', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/91877275-3b98-400a-984c-8dbb027bdbd3.png', '<p>Relacionado con la historia, imposible de perder.</p><p><br></p><p>Tan pronto uses la tarjeta de seguridad del garaje para huír de la comisaría, el trofeo saltará.</p>', ''),
	(1370, 31, 'Pirateo completo', 'Completa el segmento de Ada.', 'BRONCE', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/1d224711-265b-4b91-b11f-76446c6c9a2e.png', '<p>Relacionado con la historia, imposible de perder.</p><p>Al jugar la campaña de Leon habrá un segmento que jugarás con Ada. Al final de éste obtendrás el trofeo.</p>', ''),
	(1371, 31, 'Juguemos al escondite', 'Completa el segmento de Sherry.', 'BRONCE', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/d3498a65-64ba-4f76-b4df-0515b376c4c3.png', '<p>Relacionado con la historia, imposible de perder.</p><p>Jugando la campaña de Claire habrá un segmento que en el que jugarás como Sherry. Al terminar, el trofeo te saltará.</p>', ''),
	(1372, 31, 'Necesitas una ducha', 'Escapa de las alcantarillas.', 'BRONCE', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/5a5a1439-73d3-4152-8b28-acf169782471.png', '<p>Relacionado con la historia, imposible de perder.</p><p>Saltará una vez resuelvas el puzzle del ajedrez y tomes el teleférico para huír de las cloacas.</p>', ''),
	(1373, 31, 'Nace un héroe', 'Completa la historia de León.', 'PLATA', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/8c5ab4ee-ca5e-4791-80b7-15a059709d68.png', '<p>Relacionado con la historia, imposible de perder.</p><p>Una vez completes el juego con Leon en cualquiera de los dos escenarios, el trofeo saltará.</p>', ''),
	(1374, 31, 'Nace una heroína', 'Completa la historia de Claire.', 'PLATA', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/4ff56ca5-51fa-42ec-87cd-3cd8b2248dad.png', '<p>Relacionado con la historia, imposible de perder.</p><p>Una vez completes el juego con Claire en cualquiera de los dos escenarios, te saltará.</p>', ''),
	(1375, 31, 'Paraguas con agujeros', 'Sea testigo del verdadero final.', 'PLATA', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/fcf38ba1-eb92-40a7-be7e-b27a8e761f74.png', '<p>Relacionado con la historia, imposible de perder.</p><p>Se obtiene al jugar el escenario B (segunda pasada) con cualquiera de los dos personajes (dependerá de con quién jugaste el escenario A).</p>', ''),
	(1376, 31, 'Manual de supervivencia', 'Combina dos elementos juntos.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/d29d398b-a809-4de6-bb01-63d48561f52e.png', '<p>Se obtiene al mezclar dos objetos para obtener otro. Muy fácil conseguirlo. Puedes hacerlo con hierbas o la pólvora para fabricar munición, así como con otros utensilion.</p><p>En teoría es perdible, aunque a no ser que te animes a sacar en trofeo "Frugal" en tu primera pasada, dudo mucho que lo pierdas.</p><p>Imposible de perder.</p>', ''),
	(1377, 31, 'Bolsillos extra', 'Aumente sus espacios de inventario.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/02de34a6-5526-4a91-8553-e6bcf13b29ad.png', '<p>Como parte del juego, encontrarás unas mochilas que te aumentarán los espacios en el ársenal, tan solo consígue una y el trofeo te saltará.</p><p>Para más información ver trofeo <strong>Insondable</strong></p>', ''),
	(1378, 31, 'Esto es personal', 'Personaliza un arma.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/1bfb7e9f-9dcf-4bdf-8fcb-1d6b31bdbd02.png', '<p>Para conseguirlo debes encontrar las partes de un arma y mezclarlas con la misma. Es perdible puesto que puedes terminar el juego sin hacerlo una sola vez, pero es muy fácil y recomendable hacerlo. Encontrarás varias de las partes en casilleros que tendrás que abrir para sacar el platino.</p>', ''),
	(1379, 31, 'Ni pistola ni pistolo', 'Derrota a un enemigo con un cuchillo.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/0c6d3012-0af8-4373-adfe-2591208ac3a7.png', '<p>Debes matar a un enemigo con el cuchillo. A diferencia del juego original, aquí el daño será más considerable; sin embargo, un solo cuchillo no se mantendrá estable todo el tiempo. Habrá varios durante el juego.</p><p>El trofeo es perdible porque puedes terminar el juego sin matar un solo enemigo con el cuchillo.</p>', ''),
	(1380, 31, '¡Llévate esto!', 'Contraataca con un arma secundaria.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/ea003b71-1891-4742-99e7-11998e959b7d.png', '<p>Lo obtendrás al utilizar un subarma contra un enemigo, que puede ser el puñal(cuchillo) o una granada.</p><p>Si estás apunto de ser atacado y tienes una de estas armas en tu poder, nada más presiona L1 cuando la consola te lo indique y basta,</p>', ''),
	(1381, 31, 'En lista de espera', 'Utilice tablas de madera para tapar una ventana.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/8e5256af-9b0c-4d4d-b7fa-f22ec17163e7.png', '<p>A lo largo del juego irás encontrando tablas de madera para poner en las ventanas. Hazlo en una ventana abierta para evitar la entrada de zombies y el trofeo será tuyo.</p>', ''),
	(1382, 31, 'Mapachicidio', 'Destruye a un Sr. Mapache.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/fe91c5d2-6124-4b49-aa12-de78abe2c2db.png', '<p>Debes romper un Mr. Raccoon.</p><p>Para más información consultar trofeo <strong>Mapachicido total</strong></p>', ''),
	(1383, 31, 'Una mente abierta', 'Abra una caja fuerte portátil.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/b46e8215-252d-426e-8877-32c07aa23040.png', '<p>Debes abrir una caja fuerte portatil, en el juego encontrarás dos. Dejo un video que ayuda a encontrarlas.</p><p><br></p><p>Ten encuenta que la secuencia de botones que debes presionar es alazar, por lo tanto no hay "una única" solución al puzzle. Sin embargo, no es muy difícil de resolver.</p>', 'https://www.youtube.com/watch?v=6BwZrOAdlPg'),
	(1384, 31, 'Aprendiz de ladrón', 'Abra una caja fuerte de marcación.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/b32faa82-78d1-40e5-9cf6-587cdae4bb16.png', '<p>Debes abrir una caja fuerte. El trofeo es perdible porque puedes terminar el juego sin abrir ni una.</p><p>Para más información, ver trofeo <strong>Master of Unlocking</strong></p>', ''),
	(1385, 31, '¡Que aproveche!', 'Dispara la granada que le diste a un enemigo.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/5587d7d4-6fa0-42e8-a844-becb2df84990.png', '<p>Una vez un enemigo cualquiera te agarre y tengas una granada en tu poder, solo presiona L1 en el momento indicado, te haces soltar y luego de la explosión, el trofeo será tuyo.</p><p>Es perdible porque en teoría puede completarse el juego sin usar granadas.</p>', ''),
	(1386, 31, 'Redada zombi', 'Mata a 3 enemigos a la vez con un arma secundaria.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/e5014ebc-1527-4e98-8b6c-05f55b074164.png', '<p>Se puede hacer con contra-ataque, pero es mejor arrojar la granada. Debe arrojar la granada apuntando con L1 presionando R2.</p><p>Si has matado a tres zombies a la vez, el trofeo será tuyo.</p><p>Dejo un video, pero habrá más oportunidades para hacerlo, solo conserva las granadas explosivas hasta que lo obtengas:</p>', 'https://www.youtube.com/watch?v=3mwL2Cj99lk'),
	(1387, 31, ' Tiro al plato', 'Dispara a un perro zombi o a un lamedor en el aire.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/0973671b-2861-496b-89a2-953c51112537.png', '<p>Debes dispararle a un perro o un licker cuando están en el aire.</p><p>Puedes hacerlo mientras saltan a atacarte, o en el caso de los lickers, cuando caen del techo <strong>así lo conseguí yo</strong>.</p>', ''),
	(1388, 31, ' ¿Oyes ese pitido?', 'Deja sordo a un licker.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/35fef590-abf5-4da3-90a5-d25c6a6c31d5.png', '<p>Se consigue usando una granada flash contra un licker, puede ser arrojándola o en contraataque.</p>', ''),
	(1389, 31, 'No te va a hacer falta', 'Quítale el sombrero a Tyrant de un disparo a la cabeza.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/7ec5670f-5096-49b8-929e-950ab10307c9.png', '<p>Cuando veas a Tyrant o a mr X, dispárale a la cabeza para mandar a volar el sombrero.</p>', ''),
	(1390, 31, '¡Te tengo!', 'Derrota al G (Fase 2) usando la grúa sólo una vez.', 'PLATA', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/a098a61f-1111-408e-b255-8dbd23c15094.png', '<p>Este trofeo es altamente perdible, por lo cual, se recomienda hacer un guardado de seguridad justo después de puzzle del ajedrez.</p><p><br></p><p>Durante tu segundo enfrentamiento con William Birkin mutado, podrás derrotarlo usando la grua dos veces; sin embargo, este trofeo consiste en hacerlo una sola vez.</p><p><br></p><p>Para ello, primero lo debilitas bastante con tus armas y luego utilizas la grua. Si hiciste todo bien debería ser arrastrado de esa forma al abismo.</p><p><br></p><p>Recomendable hacerlo en dificultad asistida, ya que este enemigo puede hacer mucho daño y varios de sus ataques son difíciles de evadir. Si has hecho todo bien, el trofeo saltará tan pronto la grua golpée a William Birkin o al G virus (como prefieras llamarlo).</p>', 'https://www.youtube.com/watch?v=PFb8RYTZBqM'),
	(1391, 31, 'Cazatesoros', 'Encuentra 2 objetos ocultos con pistas fotográficas.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/a305fb92-cee9-4202-b7bd-42d3efc29919.png', '<p>En el juego encontraras unas cintas de película que al ser reveladas en el cuarto oscuro, mostrarán la ubicación de unos items escondidos. Debe tomarlos para que el trofeo te salte.</p>', 'https://www.youtube.com/watch?v=CWLZNQamq9Q'),
	(1392, 31, 'Insondable', 'Expande al máximo los espacios del inventario.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/4e3b524b-dfce-4acd-87b9-d5a5b17f9a32.png', '<p>Debes conseguir todas las mochilas de expansión de tu arsenal personal, serán 6 en total. En modo Hardcore solo encontrarás 3, por lo que no será posible obtener este trofeo en esa dificultad.</p>', 'https://www.youtube.com/watch?v=TOod-1HlBPE'),
	(1393, 31, 'Espía escurridiza', 'Termina la parte de Ada usando solo el visualizador EMF.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/9acd1fde-e865-413c-8bff-4464514cffd3.png', '<p>Durante el segmento que jugarás con Ada obtendrás un visualizador que servirá para hackear los circuitos electrónicos. El trofeo consiste en terminar este segmento sin usar nada más que el artefacto nombrado anteriormente. Eso quiere decir que no puedes disparar ni una bala (independientemente de si da o no en el blanco, el trofeo se desactiva) y de no usar las granadas.</p><p><br></p><p>Duante el segmento de Ada habrá tres coleccionable; uno de ellos será un Mr. Raccoon al que tendrás que dispararle, causando así que el trofeo no te salte si estás en plan de buscar coleccionables. Si no quieres esperarte a otra pasada, puedes hacer dos guardados en la máquina de escribir poco antes de entrar en la incineradora,de esta forma puedes conseguir el mr. Raccoon normalmente y en otro pasar todo el segmento sin disparar.</p>', 'https://www.youtube.com/watch?v=KYGJf2gwiBQ'),
	(1394, 31, 'Joven prófuga', 'Durante la parte de Sherry, huye de la habitación en 60 segundos.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/6cff8f8d-c908-4149-ac10-2f3622e935f0.png', '<p>Durante el segmento de Sherry, debes huír del lugar en el que estás en 60 segundos o menos.</p><p><br></p><p>Se consigue con un poco de maña; además, no hay que fidarse de un video, ya que el puzzle de los cubos cambiará de manera aleatoria cada vez que juegues. Sin embargo, dejo un video para que se hagan una idea.</p><p><br></p><p>Si vez que no lo vas a conseguir, simplemente sales del juego y vuelves a cargar la partida(en dificultad asistida o estándar empezando el segmento de Sherry). Además, se recomienda hacer un guardado extra por seguridad.</p>', 'https://www.youtube.com/watch?v=vD3NS6EhSCQ'),
	(1395, 31, 'El tiempo es oro', 'Derrota al G (Fase 4) cuando queden +4 min. para la explosión.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/361a279b-dd5a-481f-9d40-d9c4ca1c1746.png', '<p>Este trofeo solo puede obtenerse jugando con Claire. Para ello debes derrotar a William Birkin o al G cuando falten 4 minutos o más para la detonación. Evidentemente, entre menor sea la dificultad del juego mejor y si vez que no lo vas a conseguir, pueder reiniciar la partida.</p>', 'https://www.youtube.com/watch?v=LNNrv82MTss'),
	(1396, 31, 'En un santiamén', 'Derrota al Super Tyrant cuando queden +5 min. para la explosión.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/6f4da134-54ee-4a4c-a825-1bc9f572aad3.png', '<p>Este trofeo solo se puede conseguir jugando con Leon. Consiste en derrotar a super Tyrant faltando 5 minutos o más para la detonación. Evidentemente, entre menor sea la dificultad del juego, mejor. Usa tus mejores armas.</p>', 'https://www.youtube.com/watch?v=w7YchszV5_0'),
	(1397, 31, 'Bibliotecario', 'Lea todos los archivos.', 'BRONCE', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/3f8e00a3-0ed2-4bec-8142-f9748b5b7b5c.png', '<p>Debes leer todos los documentos del juego. Como ayuda, una vez leído el documente éste quedará archivado en la sección de documentos al abrir tu arsenal personal. No se pueden conseguir todos en una pasada, puesto que hay algunos que son exclusivos de un personaje y un escenario.</p><p><br></p><p>Para más información consulta: Master of Unlocking, sin embargo, este video asume que empiezas jugando el escenario A con Leon.</p>', ''),
	(1398, 31, 'Mapachicidio total', 'Destruye todos los Mr. Raccoons.', 'PLATA', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/672fd097-89d2-46cd-abb5-36edcb17a8b0.png', '<p>Debes destruír todos los Mr. Raccoon del juego, son 15 en total y no se pueden conseguir todos en una sola pasada, puesto que habrá algunos que solo podrás conseguir con uno de los personajes.</p><p><br></p><p>8 de ellos pueden conseguirse con ambos personajes (5 en la estación de policía, 1 en las cloacas y 2 en el laboratorio)</p><p>3 se consiguen solo con Claire (1 en la estación de policía y 2 detrás de la estación y en el orfanato)</p><p>3 se consiguen solo con Leon (1 en la estación de policía y 2 en las cloacas)</p><p>1 se consigue con cualquiera de los personajes pero SOLO jugando el escenario B justo al principio del juego en unos arbustos.</p><p><br></p>', 'https://www.youtube.com/watch?v=bnfOq8ZROaY'),
	(1399, 31, 'Master of Unlocking', 'Abre todas las cajas y cerraduras del juego.', 'PLATA', 0, 0, 1, 'https://img.psnprofiles.com/trophy/m/16679/b9ea1239-6182-4839-87fe-b3d695a0a07f.png', '<p>Debes abrir todos los cerrojos y cajas fuertes del juego; lo puedes hacer en cualquiera de los cuatro escenarios y en una sola pasada.</p>', 'https://www.youtube.com/watch?v=CmAbXqJwF84'),
<<<<<<< HEAD
	(1400, 31, 'Leon S.Kennedy', 'Completa la historia de Leon en Estándar o Hardcore con rango S.', 'ORO', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/ad8722f1-ec57-43e2-8426-379a4c84e6fb.png', '<p><br></p>', ''),
=======
	(1400, 31, 'Leon S.Kennedy', 'Completa la historia de León en Estándar o Hardcore con rango S.', 'ORO', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/16679/ad8722f1-ec57-43e2-8426-379a4c84e6fb.png', '<p><br></p>', ''),
