	(1422, 34, 'Coleccionista de monedas: principiante', 'Recoger efectivo: 10,000', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/12606/60bf65c3-d693-46a4-954b-d54cb4e4d6c2.png', '', ''),
