	(1426, 34, 'Mayorista: Principiante', 'Vender artículos: 25', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/12606/750c3c89-8e46-4300-a0f5-b0f07a6c178c.png', '', ''),
	(1427, 34, 'Mayorista: Intermedio', 'Vender artículos: 150', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/12606/399198e8-9b96-476d-b98d-1b02389d6783.png', '', ''),
	(1428, 34, 'Mayorista: Experto', 'Vender artículos: 1,000', 'BRONCE', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/12606/ea3e8dc7-e435-439b-aada-ad9f9dbc2735.png', '', ''),
	(1429, 34, 'Mayorista: Élite', 'Vender artículos: 8,000', 'BRONCE', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/12606/95f64cfd-7b48-4bf6-8a91-a283dc2b68ed.png', '', ''),
	(1430, 34, 'Artesano: Principiante', 'Artículos de artesanía: 5', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/12606/eda06f55-7b74-4c3d-9bf5-550509ce40a9.png', '', ''),
	(1431, 34, 'Artesano: Intermedio', 'Artículos de artesanía: 20', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/12606/16426cde-5bb7-4532-9269-c8f593b13408.png', '', ''),
