	(1433, 34, 'Artesano: Élite', 'Artículos de artesanía: 500', 'BRONCE', 0, 0, 0, 'https://img.psnprofiles.com/trophy/m/12606/36c3e5d1-006e-4ef8-b438-77f800b4a4de.png', '', ''),
